import { GoogleGenAI, Type, Schema } from "@google/genai";
import { 
  SeedGeneratorParams, 
  AuthorMix, 
  CalibrationMode, 
  VoicePreset, 
  SeedExpansionParams, 
  ProseGenerationParams, 
  RevisionParams, 
  BookChapter, 
  ProseStructure,
  ExpansionDepth,
  ExpansionLength,
  ExpansionFormat,
  ExpansionMode,
  BiomeType,
  WeatherMode,
  SeasonalMode,
  WildlifeFocus,
  RevisionFocus,
  Seed
} from "../types";
import { AUTHOR_DEFINITIONS, VOICE_PRESET_DETAILS } from "../constants";

const GEMINI_MODEL = "gemini-3-pro-preview";

const getApiKey = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables.");
  }
  return apiKey;
};

// --- Helper to build mix string ---
const formatMixPrompt = (mix: AuthorMix): string => {
  const activeAuthors = AUTHOR_DEFINITIONS
    .map(def => ({ ...def, val: mix[def.id] }))
    .filter(a => a.val > 0);

  if (activeAuthors.length === 0) return "Standard Strandline Tone (No specific author bias).";

  return activeAuthors
    .map(a => `${a.name}: ${a.val}% influence (${a.traits})`)
    .join('\n');
};

// --- MODULE B: SEED GENERATOR ---
export const generateStrandlineSeeds = async (params: SeedGeneratorParams, customMix?: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  let voiceInstructions = "";

  if (params.voicePreset === VoicePreset.CustomCalibration && customMix) {
    voiceInstructions = `
STRANDLINE AUTHOR VOICE ENGINE (CUSTOM CALIBRATION):
The user has configured a custom mixing desk. Blend the following authors with the specified intensity (0-100):

${formatMixPrompt(customMix)}

INSTRUCTIONS:
Synthesize these specific inputs into a coherent voice.
• High intensity (70-100%): Dominant stylistic features, sentence structure, and worldview.
• Medium intensity (30-60%): Frequent tonal coloring, specific vocabulary, and pacing.
• Low intensity (1-25%): Subtle flavor, occasional motifs, or specific observational habits.
    `;
  } else {
    // Standard Presets Logic
    const details = VOICE_PRESET_DETAILS[params.voicePreset];
    const presetDesc = details 
      ? `\nPRESET DEFINITION:\nAUTHORS: ${details.authors}\nKEYWORDS: ${details.keywords}\nEFFECTS: ${details.effects}` 
      : "";

    voiceInstructions = `
STRANDLINE AUTHOR VOICE ENGINE:
The user has selected the '${params.voicePreset}' voice.
Blend the influences of the authors associated with the selected Voice Preset ONLY as tonal gravity and rhythm.${presetDesc}
    `;
  }

  // Format Array Params for Prompt
  const formatArray = (val: string | string[]) => Array.isArray(val) ? val.join(' + ') : val;

  // Construct Geography Context based on Mode
  let geographyContext = "";
  let routeInstructions = "";

  if (params.useRouteMode) {
      const stops = params.waypoints && params.waypoints.length > 0 ? ` via [${params.waypoints.join(', ')}]` : '';
      const contextInjection = params.groundingContext 
        ? `\nREAL-WORLD ROUTE DESCRIPTION: ${params.groundingContext}\nINSTRUCTION: Ensure the narrative reflects these specific changing environments.` 
        : '';

      geographyContext = `
JOURNEY ROUTE: From "${params.startPoint}" to "${params.endPoint}"${stops}.
MODE: LINEAR TRAVERSE (Moving through changing biomes).${contextInjection}
      `;
      routeInstructions = `
CRITICAL INSTRUCTION ON ROUTE INTEGRITY:
The user has defined a specific LINEAR JOURNEY from "${params.startPoint}" to "${params.endPoint}".
The generated seeds MUST encapsulate the FULL ARC of this journey.
- Do NOT generate a seed about just one spot along the way.
- The 'Premise' must explicitly frame the text as a travelogue covering the entire distance (A -> B).
- The 'Structural Suggestion' must explicitly map the chapters from the Starting Location, through the Transition Zones/Waypoints, to the Destination.
- Account for the change in geology/biome/atmosphere as the narrator moves from Start to End.
- Negative Constraint: Do not write a static vignette. This is a dynamic traverse.
      `;
  } else {
      const contextInjection = params.groundingContext 
        ? `\nREAL-WORLD ECOLOGICAL CONTEXT: ${params.groundingContext}` 
        : '';
      geographyContext = `
LOCATION: ${params.locationName || "Unknown Location"}
MODE: GENIUS LOCI (Deep dive into a single place).${contextInjection}
      `;
  }

  const prompt = `
Generate ${params.seedCount} high-quality Strandline-style narrative seeds.

VARIABLES:
${geographyContext}
BIOME: ${formatArray(params.biomeType)}
WEATHER MODE: ${formatArray(params.weatherMode)}
SEASON: ${formatArray(params.seasonalMode)}
WILDLIFE FOCUS: ${formatArray(params.wildlifeFocus)}
VOICE PRESET: ${params.voicePreset}
NARRATOR MODE: ${formatArray(params.narratorMode)}
JOURNEY SCALE: ${params.journeyScale}
JOURNEY MODE: ${formatArray(params.journeyMode)}
STRUCTURE MODE: ${formatArray(params.structureMode)}

${voiceInstructions}

Do NOT mention the authors in the written output.
Let their presence be inferred through pacing, imagery, depth of ecological noticing, mythic atmosphere, and sensory anchoring.

CRITICAL INSTRUCTION ON JOURNEY MODE:
The selected JOURNEY MODE (${formatArray(params.journeyMode)}) must physically dictate the narrative perspective:
- If 'Paddle' or 'Kayak': Perspective must be water-level, rhythmic, silent, and vulnerable to tides/currents.
- If 'Foot' or 'Hike': Perspective must be tactile, ground-level, slower-paced, and physically exerting.
- If 'Road' or 'Rail': Perspective must be framed by windows, transient, moving through contrasting zones rapidly, detached yet observant.
- If 'Sail': Perspective must be dictated by wind, charts, and the mechanics of the vessel.
- If 'Stationary': Perspective must be deep, time-lapse observation of a single point changing over time.
- If 'Swim': Perspective must be immersive, cold, fluid, and bodily.
- If 'Dive' or 'Snorkel': Perspective must be submarine, weightless, breath-focused, and alien.

${routeInstructions}

REQUIREMENTS:
• Strong specificity to LOCATION + BIOME.
• Weather and wildlife integral, not decorative.
• Voice consistent with selected preset or mix.
• The 'PREMISE' must explicitly reflect the mode of travel.
• The 'STRUCTURAL SUGGESTION' must reflect the pacing of the journey.
• No generic filler.
• Seeds must feel like “the beginning of a Strandline book.”

OUTPUT FORMAT:
Return a JSON object containing an array of seeds under the key "seeds".
`;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        temperature: 0.85,
        topP: 0.95,
        maxOutputTokens: 8192,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            seeds: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  premise: { type: Type.STRING },
                  motifs: { type: Type.ARRAY, items: { type: Type.STRING } },
                  toneProfile: { type: Type.STRING },
                  structuralSuggestion: { type: Type.STRING }
                },
                required: ["title", "premise", "motifs", "toneProfile", "structuralSuggestion"]
              }
            }
          },
          required: ["seeds"]
        }
      }
    });

    const json = JSON.parse(response.text || "{\"seeds\": []}");
    return JSON.stringify(json.seeds || []);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

// --- MODULE B (EXTENSION): REMIXER ---
export const remixStrandlineSeeds = async (seeds: Seed[], mix: AuthorMix): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });
    const voiceInstruction = formatMixPrompt(mix);

    // Format input seeds for the prompt
    const seedContext = seeds.map((s, i) => `
PARENT SEED ${i + 1}:
Title: ${s.title}
Premise: ${s.premise}
Motifs: ${s.motifs.join(', ')}
    `).join('\n');

    const prompt = `
You are the Strandline Grafting Engine.
Your task is to take ${seeds.length} distinct narrative seeds and "GRAFT" them together to create 3 NEW, HYBRID seeds.

PARENT MATERIAL:
${seedContext}

VOICE PROFILE:
${voiceInstruction}

INSTRUCTIONS:
1. Identify the core conflict or atmospheric pressure in each Parent Seed.
2. SYNTHESIZE these elements. Do not just list them side-by-side. Create a new narrative that requires BOTH elements to exist.
   - Example: If Parent A is "Coastal Ghost Story" and Parent B is "Industrial Rail Journey", the Child should be "A ghost story about a haunted rail line running along a collapsing coast."
3. Resolve any contradictions (e.g., Desert vs Arctic) by creating a "Transition Zone" or a "Surreal Climate Shift".
4. Generate 3 distinct "Child" seeds based on this synthesis.

OUTPUT FORMAT:
Return a JSON object containing an array of seeds under the key "seeds".
    `;

    try {
        const response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                temperature: 0.9,
                maxOutputTokens: 8192,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        seeds: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    title: { type: Type.STRING },
                                    premise: { type: Type.STRING },
                                    motifs: { type: Type.ARRAY, items: { type: Type.STRING } },
                                    toneProfile: { type: Type.STRING },
                                    structuralSuggestion: { type: Type.STRING }
                                },
                                required: ["title", "premise", "motifs", "toneProfile", "structuralSuggestion"]
                            }
                        }
                    },
                    required: ["seeds"]
                }
            }
        });
        const json = JSON.parse(response.text || "{\"seeds\": []}");
        return JSON.stringify(json.seeds || []);
    } catch (error) {
        console.error("Remix Error:", error);
        throw error;
    }
}

// --- REAL-WORLD GROUNDING (SEARCH - SINGLE LOCATION) ---
export const analyzeLocationWithSearch = async (locationName: string): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const prompt = `
  You are an Ecological Scout.
  Perform a Google Search for the location: "${locationName}".

  Based on the REAL-WORLD geography, ecology, and current conditions of this place, map it to the provided Enums.

  AVAILABLE ENUMS (Select the most accurate matches):

  Biomes: ${Object.values(BiomeType).join(', ')}
  Weather: ${Object.values(WeatherMode).join(', ')}
  Season: ${Object.values(SeasonalMode).join(', ')}
  Wildlife: ${Object.values(WildlifeFocus).join(', ')}

  INSTRUCTIONS:
  1. Identify the primary biomes.
  2. Estimate the most likely dramatic weather.
  3. Identify the key wildlife.
  4. Provide a brief 1-sentence 'Ecological Report'.

  OUTPUT:
  Return a JSON object.
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
           type: Type.OBJECT,
           properties: {
              foundLocation: { type: Type.STRING },
              suggestedBiomes: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestedWeather: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestedSeason: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestedWildlife: { type: Type.ARRAY, items: { type: Type.STRING } },
              ecologicalReport: { type: Type.STRING }
           }
        }
      }
    });
    const json = JSON.parse(response.text || "{}");
    return json;
  } catch (error) {
    console.error("Grounding Error:", error);
    // Return soft error fallback to prevent app crash on quota limit
    return {
        foundLocation: locationName,
        suggestedBiomes: [],
        suggestedWeather: [],
        suggestedSeason: [],
        suggestedWildlife: [],
        ecologicalReport: "⚠️ Auto-Grounding unavailable (Quota Limit). Please configure settings manually."
    };
  }
};

// --- REAL-WORLD GROUNDING (SEARCH - ROUTE) ---
export const analyzeRouteWithSearch = async (start: string, end: string, waypoints: string[]): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });

    const viaText = waypoints.length > 0 ? ` via ${waypoints.join(', ')}` : '';

    const prompt = `
    You are a Route Scout.
    Perform a Google Search to analyze the travel route from "${start}" to "${end}"${viaText}.

    Based on the REAL-WORLD geography of this ROUTE:
    1. Identify the changing BIOMES along the path (e.g. starting at Coast, moving through Industrial Hinterland, ending in Forest).
    2. Suggest the likely weather patterns for this traverse.
    3. Generate a "Route Description" that breaks the journey into distinct ecological legs.

    AVAILABLE ENUMS:
    Biomes: ${Object.values(BiomeType).join(', ')}
    Weather: ${Object.values(WeatherMode).join(', ')}

    OUTPUT:
    Return a JSON object.
    `;

    try {
      const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
             type: Type.OBJECT,
             properties: {
                routeDescription: { type: Type.STRING },
                suggestedBiomes: { type: Type.ARRAY, items: { type: Type.STRING } },
                suggestedWeather: { type: Type.ARRAY, items: { type: Type.STRING } }
             }
          }
        }
      });
      const json = JSON.parse(response.text || "{}");
      return json;
    } catch (error) {
      console.error("Route Analysis Error:", error);
      // Return soft error fallback to prevent app crash on quota limit
      return {
          routeDescription: "⚠️ Route Scouting unavailable (Quota Limit). Please configure settings manually.",
          suggestedBiomes: [],
          suggestedWeather: []
      };
    }
  };

// --- MODULE A: VOICE LAB CALIBRATION ---
export const generateVoiceProfile = async (mix: AuthorMix, mode: CalibrationMode): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const activeAuthors = AUTHOR_DEFINITIONS.filter(def => mix[def.id] > 0);

  const mixDescription = activeAuthors.length > 0
    ? activeAuthors.map(a => `${a.name}: ${mix[a.id]}`).join('\n')
    : "No authors selected (Neutral Tone)";

  const prompt = `
You are the Strandline Voice Calibration Engine.
The user has configured a literary mixing desk with the following settings (0-100 intensity):

${mixDescription}

TASK:
Generate a detailed VOICE PROFILE that captures the exact tonal blend implied by these sliders.

For each author with non-zero influence:
• Consider what their tone contributes (cadence, atmosphere, moral texture, mythic residue, ecological attention, etc.)
• Consider how this influence affects: pacing, imagery, sentence rhythm, sensory detail, narrator stance.

Then:
• Merge all influences into a SINGLE, COHERENT voice description.
• Generate 5–10 “Voice Guardrails”.
• Generate a “Cadence Profile” (sentence length, rhythm, musicality).
• Generate a “Lexicon Palette” (preferred words, field-terms, textures).
• Generate “Atmospheric Bias” (how light, weather, wildlife appear).

OUTPUT MODE: ${mode}
`;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { 
        temperature: 0.7,
        maxOutputTokens: 8192 
      }
    });
    return response.text || "No profile generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const generateVoiceSample = async (mix: AuthorMix): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });
    const voiceInstruction = formatMixPrompt(mix);

    const prompt = `
    You are the Strandline Voice Sampler.

    VOICE PROFILE:
    ${voiceInstruction}

    TASK:
    Write a single, high-quality paragraph (approx. 100 words) describing a simple object found in nature (e.g., a sea-washed stone, a hawk's feather, a piece of driftwood, or a rusted piece of iron).

    GOAL:
    Demonstrate the specific rhythm, vocabulary, and atmospheric pressure of the current Author Mix. 
    This is a "Blind Taste Test" for the user to hear the voice.

    OUTPUT:
    Just the paragraph.
    `;

    try {
        const response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: { temperature: 0.9, maxOutputTokens: 1024 }
        });
        return response.text || "";
    } catch (error) {
        console.error("Sample Gen Error:", error);
        throw error;
    }
}

// --- MODULE C: SEED EXPANDER ---
export const expandStrandlineSeed = async (params: SeedExpansionParams, mix: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);
  const depthInstruction = params.expansionDepth || ExpansionDepth.Standard;
  const lengthInstruction = params.expansionLength || ExpansionLength.Standard;
  const formatInstruction = params.expansionFormat || ExpansionFormat.BulletPoints;
  const focusInstruction = params.customFocus ? `USER DIRECTIVE / FOCUS: "${params.customFocus}"` : "No specific user focus provided.";

  // --- SPECIAL LOGIC FOR CHAPTER ARCHITECT MODE ---
  if (params.expansionMode === ExpansionMode.BookArchitecture) {
    // Map existing inputs to Chapter Architect Inputs
    let chapterCount = "8-10";
    if (params.expansionLength === ExpansionLength.Concise) chapterCount = "4-6";
    if (params.expansionLength === ExpansionLength.Comprehensive) chapterCount = "12-15";

    let wordCountTarget = "2500";
    if (params.expansionDepth === ExpansionDepth.BroadStrokes) wordCountTarget = "1500";
    if (params.expansionDepth === ExpansionDepth.AtomicDetail) wordCountTarget = "4000";

    const prompt = `
You are the CHAPTER ARCHITECT.

Using the BOOK BRIEF (Source Seed) and the selected settings:

Inputs:
• Chapter Count = ${chapterCount}
• Word Count Target per Chapter = ${wordCountTarget}
• Voice Mix = \n${voiceInstruction}
• Directives = ${focusInstruction}

BOOK BRIEF (Seed):
"${params.seedText}"

TASK:
Generate the full CHAPTER STRUCTURE for a book based on this brief.

For each chapter provide:

1) Chapter Title (haunting, poetic, maritime, specific)
2) 2–4 paragraph summary based on the narrative arc
3) Narrative movement (what shifts/travels)
4) Weather system (specific and real to the biome)
5) Natural history layer (specific species, tides, marine life, geology)
6) Human history trace (wrecks, ports, migration, ruins)
7) Psychological movement (inner change of narrator)
8) Research inserts (4–6 specific topics to research/include)
9) Word Count Target: ${wordCountTarget}

Rules:
• Strandline pacing: slow, attentive, tidal
• Emotional arc = subtle but cumulative
• No clichés or filler
• Consistent geography and sensory logic
• Each chapter makes the coast (or landscape) more knowable

OUTPUT:
Return a structured JSON object with a "chapters" key containing an array of chapter objects.
`;

    try {
      const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: prompt,
        config: { 
          temperature: 0.8,
          maxOutputTokens: 8192,
          responseMimeType: "application/json",
          responseSchema: {
             type: Type.OBJECT,
             properties: {
                chapters: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            title: { type: Type.STRING },
                            summary: { type: Type.STRING },
                            details: { type: Type.STRING }
                        }
                    }
                }
             }
          }
        }
      });
      return response.text || "{}";
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }

  // --- STANDARD EXPANSION LOGIC ---
  const prompt = `
You are the Strandline Expansion Engine (Module C).
Your task is to take a narrative "Seed" and expand it into a fully structured ${params.expansionMode} based on the user's specific Voice Profile and Directives.

VOICE PROFILE (Active Mix):
${voiceInstruction}

NARRATIVE SEED (Source Material):
"${params.seedText}"

STEERING INSTRUCTIONS:
DETAIL DENSITY: ${depthInstruction}
TARGET LENGTH: ${lengthInstruction}
OUTPUT FORMAT: ${formatInstruction}
${focusInstruction}

CRITICAL INSTRUCTION ON DENSITY, LENGTH & FORMAT:
- If 'Broad Strokes': Focus on the large architectural movements of the piece. Do not get bogged down in minutiae.
- If 'Atomic Detail': The output must be dense with specific naming (species, geology, specific colors), micro-observations, and sensory precision.
- If 'Concise' Length: Keep descriptions brief, punchy, and to the point.
- If 'Comprehensive' Length: Explore every angle deeply. Do not summarize; expand.
- If 'Bullet Points' Format: Use clean, nested lists for readability.
- If 'Flowing Prose' Format: Write in complete paragraphs/sentences, avoiding lists where possible.
- If 'Structured Headers' Format: Use clear, bold headers with distinct sections.

TASK:
Expand this seed into a ${params.expansionMode}.

IF MODE IS "Sensory Map":
- Break the seed down into 5 distinct sensory zones (Visual, Auditory, Tactile, Olfactory, Proprioceptive).
- For each zone, provide details consistent with the Voice Profile and Density setting.

IF MODE IS "Narrative Arc":
- Outline a beginning, middle, and end.
- Identify the "Inciting Observation" (the moment nature catches attention).
- Identify the "Deepening" (moving into history, memory, or science).
- Identify the "Turn" (the shift in perspective).
- Identify the "Exit" (leaving the landscape changed).

IF MODE IS "Essay Structure":
- Create a header-based outline for a creative non-fiction essay.
- Suggest section titles.
- For each section, list the "Key Image" and the "Intellectual Thread".

IF MODE IS "Scene Breakdown":
- Divide the seed into 4-6 cinematic scenes.
- For each scene, define: Lighting, Primary Action, Internal Monologue, and Wildlife Interaction.

IF MODE IS "Deep Time Audit":
- Analyze the seed for deep-time potentials.
- List: Geological strata, Historical ghosts, Future-specters, Human ruins.

IF MODE IS "Ecological Web":
- Map the 'Invisible Lines': Pheromone trails, root systems, migratory paths.
- Identify 3 specific 'Symbiotic Pairs' in this landscape.
- Trace the flow of energy/nutrients through the scene.
- Highlight the non-human agency in the environment.

IF MODE IS "Psychogeographic Route":
- Map the 'Deep Topography': What lies beneath the pavement/soil?
- Identify 'Spectral Nodes': Places where history resurfaces or ghosts linger.
- Trace the narrator's emotional resonance against the physical path.
- Overlay archival memory onto present observation.

IF MODE IS "Mythic Overlay":
- Identify the 'Genius Loci' (Spirit of Place).
- Map 3 physical features to local folklore or ancient naming.
- Blur the line between what is seen (scientific) and what is believed (mythic).
- Create a sense of timelessness.

REQUIREMENTS:
- Strictly adhere to the tone of the Voice Profile.
- Maintain high literary quality.
- Do not write the full prose yet, but provide the *skeleton* and *muscle* for the prose.
`;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { 
        temperature: 0.8,
        maxOutputTokens: 8192
      }
    });
    return response.text || "No expansion generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const generateChapterBeatSheet = async (
    chapterSummary: string, 
    mix: AuthorMix,
    params: { depth: ExpansionDepth, length: ExpansionLength }
): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });
    const voiceInstruction = formatMixPrompt(mix);

    const prompt = `
You are the STRANDLINE SCENE ARCHITECT.
Your task is to take a summary of a single chapter and explode it into a detailed BEAT SHEET / SCAFFOLD ready for prose generation.

VOICE PROFILE:
${voiceInstruction}

CHAPTER SUMMARY:
"${chapterSummary}"

SETTINGS:
Depth: ${params.depth}
Length: ${params.length}

TASK:
Create a detailed, scene-by-scene beat sheet for this chapter.
For each scene (3-5 scenes per chapter):
1. HEADER (Time/Location)
2. KEY ACTION (What happens)
3. SENSORY DETAILS (Sight, Sound, Smell - specific to the author voice)
4. INTERNAL SHIFT (What changes in the narrator)
5. KEY IMAGE (The anchor visual)

OUTPUT:
A structured beat sheet.
    `;

    try {
        const response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: { temperature: 0.85, maxOutputTokens: 8192 }
        });
        return response.text || "";
    } catch (error) {
        console.error("Beat Sheet Error:", error);
        throw error;
    }
};

// --- MODULE D: PROSE BUILDER - PLANNER ---
export const planProseOutline = async (scaffold: string, mode: ProseGenerationParams['proseMode']): Promise<string[]> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });

    const prompt = `
You are the Strandline Structural Architect.
Based on the provided scaffold, breakdown the writing into 3-6 distinct, logical sections (headers).
The sections should represent the natural flow of the narrative.

SCAFFOLD:
"${scaffold}"

TARGET MODE: ${mode}

OUTPUT:
Return a JSON object with a "sections" key containing an array of section header strings.
Example: { "sections": ["I. The Arrival", "II. The Descent", "III. The Return"] }
    `;

    try {
        const response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        sections: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        }
                    },
                    required: ["sections"]
                }
            }
        });
        const json = JSON.parse(response.text || "{\"sections\": []}");
        return json.sections || [];
    } catch (error) {
        console.error("Planning Error:", error);
        return ["Section 1", "Section 2", "Section 3"]; // Fallback
    }
}

