export const generateStrandlineProse = async (params: ProseGenerationParams, mix: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);

  const structureInstructions = params.proseStructure === ProseStructure.MultiSection
    ? `
STRUCTURE REQUIREMENT: MULTI-SECTION
The user requested a multi-part structure.
• Divide the output into clear sections (e.g., I, II, III or named headers).
• Ensure there is a sense of progression between sections.
• Each section should have its own internal arc.
    `
    : `
STRUCTURE REQUIREMENT: SINGLE BLOCK
The output should be a continuous flow of prose, possibly with paragraph breaks, but no formal chapter/section headers unless intrinsically necessary.
    `;

  const prompt = `
You are the Strandline Prose Engine (Module D).
Your task is to write the prose based on the provided Scaffold/Outline, strictly adhering to the Author Voice Mix.

VOICE PROFILE (Active Mix):
${voiceInstruction}

SCAFFOLD / OUTLINE (Context):
"${params.scaffoldText}"

TARGET MODE: ${params.proseMode}
TARGET LENGTH: ${params.proseLength}
TARGET STRUCTURE: ${params.proseStructure}

INSTRUCTIONS:
Write a SUBSTANTIAL, DEEPLY TEXTURED section of creative non-fiction or narrative prose based on the scaffold above.
• The voice must be distinct. Use the specific author weights to guide vocabulary and rhythm.
• Avoid generic AI nature writing (e.g., "tapestry of colors", "symphony of sounds").
• Focus on specific names of species, clouds, and geological forms.
• Maintain a consistent rhythm.

${structureInstructions}

MODE SPECIFIC INSTRUCTIONS:
• If 'Stream of Consciousness': Focus on internal monologue, rapid associations, and memory overlap. Less concern for linear time.
• If 'Travelogue / Reportage': Focus on external observation, dialogue with locals, and concrete social facts.
• If 'Speculative Ecology': Introduce elements of future-climate estrangement or sci-fi adaptation while maintaining realism.

CRITICAL LENGTH INSTRUCTION:
The user has requested: ${params.proseLength}.
• If 'Micro' or 'Brief': Be concise, punchy, and dense.
• If 'Extended' or 'Epic': SLOW DOWN. Dwell on the sensory details of the immediate moment. Expand every observation.
• If 'Feature Article': Write a comprehensive, multi-sectioned piece. Ensure there is a strong narrative thread connecting distinct environments or ideas.

OUTPUT:
Write high-quality draft prose meeting the length requirement. Ensure the response is complete and does not cut off.
`;

  try {
    // Switch to streaming internally to ensure full content is received for large prose
    const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { 
        temperature: 0.85,
        maxOutputTokens: 32768, 
      } 
    });

    let fullText = "";
    for await (const chunk of responseStream) {
        if (chunk.text) {
            fullText += chunk.text;
        }
    }
    return fullText || "No prose generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

