export const reviseStrandlineProse = async (params: RevisionParams, mix: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);

  let tunerInstructions = "";
  if (params.sensoryTuner) {
    const { abstraction, temperature, humanPresence } = params.sensoryTuner;

    tunerInstructions = `
SENSORY TUNER CALIBRATION (Priority Instructions):
1. ABSTRACTION LEVEL: ${abstraction}%
   - 0-30: Strictly literal, documentary, optical precision.
   - 70-100: High metaphor, dream-logic, symbolic resonance, hallucinations.
   - 31-69: Balanced lyrical realism.

2. EMOTIONAL TEMPERATURE: ${temperature}%
   - 0-30: Cold, forensic, clinical, detached, objective.
   - 70-100: Warm, nostalgic, intimate, blood-close, subjective.
   - 31-69: Neutral, observant.

3. HUMAN PRESENCE: ${humanPresence}%
   - 0-30: Pristine wilderness, deep time, non-human focus, pre-history.
   - 70-100: Anthropocene, industrial traces, plastic, ruins, social context.
   - 31-69: Balanced ecology (human and nature co-existing).
    `;
  }

  // Specific Etymology Excavator Logic
  let focusInstructions = "";
  if (params.revisionFocus === RevisionFocus.EtymologicalRewilding) {
      focusInstructions = `
      ETYMOLOGICAL EXCAVATOR MODE (CRITICAL):
      • Your goal is to "rewild" the language. 
      • Aggressively replace "smooth" Latinate/Romance words with "rough" Old English, Norse, Germanic, or Celtic roots.
      • Example: Replace "observe" with "watch", "descend" with "go down", "illumination" with "light".
      • Use dialect words appropriate for Northern European landscapes if they fit (e.g., 'beck', 'fell', 'gloaming').
      • The text should feel older, harder, and more bone-deep.
      `;
  } else {
      focusInstructions = `REVISION FOCUS: ${params.revisionFocus}`;
  }

  const prompt = `
You are the Strandline Revision Engine (Module E).
Your task is to POLISH and REWRITE the provided draft to better match the Voice Mix and the Revision Focus.

VOICE PROFILE (Active Mix):
${voiceInstruction}

${focusInstructions}

${tunerInstructions}

DRAFT TEXT:
"${params.draftText}"

INSTRUCTIONS:
Rewrite the text to enhance the specific focus requested.
• Keep the core narrative but change the texture, word choice, and rhythm.
• If "Enhance Ecology": Replace generic terms with specific scientific/field terms.
• If "Fix Rhythm": Alter sentence lengths to create the "Cadence" of the voice mix.
• If "Deepen Atmosphere": Focus on light, weather, and sensory pressure.
• Unless the focus is 'Strip Back', try to MAINTAIN or EXPAND the word count. Do not summarize or truncate the draft.

OUTPUT:
The fully rewritten text. Ensure the response is complete and does not cut off mid-sentence.
`;

  try {
    // Switch to streaming internally to ensure full content is received
    const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { 
        temperature: 0.7,
        maxOutputTokens: 32768 
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
        if (chunk.text) {
            fullText += chunk.text;
        }
    }
    return fullText || "No revision generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

