          {activeTab === Tab.Generator && (
            <>
              <h2 className="text-3xl font-serif text-strand-800">Module B: Seed Generator</h2>
              <p className="text-strand-600">Cultivate the narrative soil.</p>
            </>
          )}
          {activeTab === Tab.VoiceLab && (
