// --- MODULE D: PROSE BUILDER - SECTION GENERATOR ---
export const generateProseSection = async (
    params: ProseGenerationParams, 
    mix: AuthorMix, 
    sectionTitle: string, 
    previousContext: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);

  const prompt = `
You are the Strandline Prose Engine. You are writing a SPECIFIC SECTION of a larger piece.

VOICE PROFILE:
${voiceInstruction}

CONTEXT SO FAR (The end of the previous section):
"...${previousContext.slice(-1000)}..."

CURRENT SECTION TO WRITE:
"${sectionTitle}"

OVERALL SCAFFOLD (For reference):
"${params.scaffoldText}"

INSTRUCTIONS:
- Write the full prose for the section titled "${sectionTitle}".
- Pick up the narrative thread naturally from the CONTEXT SO FAR. Ensure smooth transition.
- Do NOT repeat the section title in the output text.
- Maintain the requested prose length intensity (${params.proseLength}).
- Focus on sensory details, specific ecology, and the author voice mix.

OUTPUT:
Only the prose content for this section.
  `;

  try {
    // Increased output limit to prevent cutoff for long sections
    const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { temperature: 0.85, maxOutputTokens: 32768 }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
        if (chunk.text) {
            fullText += chunk.text;
        }
    }
    return fullText;
  } catch (error) {
    console.error("Section Gen Error:", error);
    throw error;
  }
}

