import React, { useState } from 'react';
import { AUTHOR_DEFINITIONS } from '../constants';
import { AuthorMix, CalibrationMode, VoiceAnalysisResult, VoiceSuggestions, BiomeType } from '../types';
import { generateVoiceSample } from '../services/geminiService';
import { Slider } from './Slider';
import { SparklesIcon, RefreshIcon, DiceIcon, MapIcon, ArrowRightCircleIcon, CopyIcon } from './Icons';

interface VoiceLabProps {
  mix: AuthorMix;
  onMixChange: (mix: AuthorMix) => void;
  onGenerate: (mode: CalibrationMode) => void;
  loading: boolean;
  result: VoiceAnalysisResult | null;
  onApplySuggestions?: (location: string, biomes: BiomeType[]) => void;
}

export const VoiceLab: React.FC<VoiceLabProps> = ({ mix, onMixChange, onGenerate, loading, result, onApplySuggestions }) => {

  const [sampleLoading, setSampleLoading] = useState(false);
  const [sampleResult, setSampleResult] = useState<string | null>(null);

  const totalUsed = (Object.values(mix) as number[]).reduce((sum: number, val: number) => sum + val, 0);

  const handleSliderChange = (id: string, val: number) => {
    const currentVal = mix[id as keyof AuthorMix] || 0;
    const otherTotal = totalUsed - currentVal;

    let newValue = val;
    // Prevent going over 100%
    if (otherTotal + newValue > 100) {
      newValue = 100 - otherTotal;
    }

    onMixChange({ ...mix, [id]: newValue });
  };

  const handleReset = () => {
    const zeroMix = { ...mix };
    Object.keys(zeroMix).forEach(k => zeroMix[k as keyof AuthorMix] = 0);
    onMixChange(zeroMix);
  };

  const handleRandomize = () => {
    // Reset all to 0
    const newMix = { ...mix };
    Object.keys(newMix).forEach(k => newMix[k as keyof AuthorMix] = 0);

    // Pick 3 distinct random authors
    const shuffled = [...AUTHOR_DEFINITIONS].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 3);

    // Generate random weights summing to 100
    // Generate 3 random numbers, sum them, then normalize
    const r1 = Math.random() + 0.2; // Add base to avoid too small numbers
    const r2 = Math.random() + 0.2;
    const r3 = Math.random() + 0.2;
    const sum = r1 + r2 + r3;

    const val1 = Math.round((r1 / sum) * 100);
    const val2 = Math.round((r2 / sum) * 100);
    const val3 = 100 - val1 - val2;

    newMix[selected[0].id] = val1;
    newMix[selected[1].id] = val2;
    newMix[selected[2].id] = val3;

    onMixChange(newMix);
  };

  const handleSample = async () => {
    setSampleLoading(true);
    setSampleResult(null);
    try {
        const text = await generateVoiceSample(mix);
        setSampleResult(text);
    } catch (e) {
        alert("Could not generate sample.");
    } finally {
        setSampleLoading(false);
    }
  }

  const handleCopy = (text: string) => {
      navigator.clipboard.writeText(text);
      alert("Copied!");
  }

  const handleSendToGenerator = (location: string, biomes: BiomeType[]) => {
      if (onApplySuggestions) {
          onApplySuggestions(location, biomes);
      }
  }

  return (
    <div className="space-y-8">

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end border-b border-strand-200 pb-4 gap-4">
        <div>
          <h2 className="text-2xl font-serif text-strand-800">Voice Calibration Lab</h2>
          <p className="text-strand-500 text-sm mt-1">Mix your own literary tonal fingerprint.</p>
        </div>

        <div className="flex flex-col items-end gap-2 w-full sm:w-auto">
          <div className="flex items-center gap-3">
             <span className={`text-sm font-bold ${totalUsed === 100 ? 'text-green-600' : 'text-strand-600'}`}>
                Total Mix: {totalUsed}%
             </span>
             <div className="flex gap-2 border-l border-strand-200 pl-3">
                 <button 
                    onClick={handleRandomize}
                    className="flex items-center gap-1 text-xs font-medium text-strand-700 hover:text-strand-900 bg-strand-100 hover:bg-strand-200 px-3 py-1.5 rounded transition-colors"
                    title="Blend 3 random authors"
                >
                    <DiceIcon className="w-3 h-3" />
                    Surprise Blend
                </button>
                 <button 
                    onClick={handleReset}
                    className="text-xs font-medium text-strand-400 hover:text-strand-600 hover:bg-strand-50 px-2 py-1.5 rounded transition-colors"
                >
                    Reset
                </button>
             </div>
          </div>
          <div className="w-full sm:w-64 h-2 bg-strand-100 rounded-full overflow-hidden">
             <div 
                className={`h-full transition-all duration-300 ${totalUsed === 100 ? 'bg-green-500' : 'bg-strand-400'}`} 
                style={{ width: `${totalUsed}%` }}
             ></div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-x-8 gap-y-6">
        {AUTHOR_DEFINITIONS.map((author) => (
          <Slider
            key={author.id}
            label={author.name}
            subLabel={author.traits}
            value={mix[author.id]}
            onChange={(val) => handleSliderChange(author.id, val)}
          />
        ))}
      </div>

      {/* Control Deck */}
      <div className="flex flex-col sm:flex-row justify-center gap-4 pt-6">
         <button
            onClick={() => onGenerate(CalibrationMode.VoiceDescription)}
            disabled={loading}
            className={`
              flex items-center justify-center gap-2 px-6 py-3 rounded-full font-serif font-bold text-base shadow-md transition-all
              ${loading 
                ? 'bg-strand-200 text-strand-400 cursor-not-allowed' 
                : 'bg-strand-800 text-white hover:bg-strand-900'
              }
            `}
          >
            {loading ? (
              <>
                <RefreshIcon className="w-4 h-4 animate-spin" />
                <span>Calibrating...</span>
              </>
            ) : (
              <>
                <SparklesIcon className="w-4 h-4" />
                <span>Analyze & Generate Profile</span>
              </>
            )}
          </button>

          <button
            onClick={handleSample}
            disabled={sampleLoading}
            className={`
              flex items-center justify-center gap-2 px-6 py-3 rounded-full font-serif font-bold text-base shadow-sm border border-strand-300 transition-all
              ${sampleLoading
                ? 'bg-strand-50 text-strand-400' 
                : 'bg-white text-strand-700 hover:bg-strand-50'
              }
            `}
          >
             {sampleLoading ? <RefreshIcon className="w-4 h-4 animate-spin" /> : <span>Blind Taste Test (Sample)</span>}
          </button>
      </div>

      {sampleResult && (
          <div className="bg-strand-50 rounded-xl p-6 border border-strand-200 relative animate-in fade-in duration-500 max-w-2xl mx-auto mt-4">
              <div className="absolute top-0 right-0 px-3 py-1 bg-strand-200 rounded-bl-lg text-[10px] font-bold text-strand-600 uppercase tracking-wider">
               Sample
             </div>
             <p className="font-serif text-strand-800 text-sm italic leading-relaxed">
                 "{sampleResult}"
             </p>
          </div>
      )}

      {/* ANALYSIS RESULT & SUGGESTIONS */}
      {result && (
         <div className="space-y-6 animate-in fade-in duration-500">

             {/* Text Analysis */}
             <div className="bg-white rounded-xl shadow-md border border-strand-200 p-8 relative">
                 <div className="absolute top-0 right-0 px-4 py-2 bg-strand-100 rounded-bl-lg text-xs font-bold text-strand-600 uppercase tracking-wider">
                   Voice Analysis
                 </div>
                 <pre className="whitespace-pre-wrap font-serif text-sm leading-relaxed text-strand-800 font-normal">
                    {result.profileText}
                 </pre>
             </div>

             {/* Territory Recommendations */}
             {result.suggestions && (
                 <div className="bg-strand-50 rounded-xl border border-strand-200 p-6 sm:p-8">
                     <div className="flex items-center gap-2 mb-6 border-b border-strand-200 pb-3">
                         <MapIcon className="w-5 h-5 text-strand-700" />
                         <h3 className="font-serif text-lg text-strand-800">Territory & Subject Protocol</h3>
                         <span className="text-xs text-strand-500 bg-white px-2 py-0.5 rounded border border-strand-100">
                             Based on your Author Mix
                         </span>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

                         {/* Locations */}
                         <div className="space-y-3">
                             <h4 className="text-xs font-bold text-strand-500 uppercase tracking-wider">Suggested Locations</h4>
                             {result.suggestions.suggestedLocations.map((loc, idx) => (
                                 <div key={idx} className="bg-white p-3 rounded shadow-sm border border-strand-200 flex justify-between items-center group">
                                     <span className="text-sm font-serif text-strand-800">{loc}</span>
                                     <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                         <button onClick={() => handleCopy(loc)} title="Copy" className="p-1 hover:bg-strand-100 rounded text-strand-400 hover:text-strand-600">
                                             <CopyIcon className="w-3 h-3" />
                                         </button>
                                         {onApplySuggestions && (
                                            <button 
                                                onClick={() => handleSendToGenerator(loc, result.suggestions.suggestedBiomes)} 
                                                title="Send to Seed Generator"
                                                className="p-1 hover:bg-green-100 rounded text-green-500 hover:text-green-700"
                                            >
                                                <ArrowRightCircleIcon className="w-3 h-3" />
                                            </button>
                                         )}
                                     </div>
                                 </div>
                             ))}
                         </div>

                         {/* Biomes */}
                         <div className="space-y-3">
                             <h4 className="text-xs font-bold text-strand-500 uppercase tracking-wider">Relevant Biomes</h4>
                             <div className="flex flex-wrap gap-2">
                                 {result.suggestions.suggestedBiomes.map((biome, idx) => (
                                     <span key={idx} className="bg-white px-3 py-1.5 rounded-full border border-strand-200 text-xs font-medium text-strand-700">
                                         {biome}
                                     </span>
                                 ))}
                             </div>
                             {onApplySuggestions && (
                                <button 
                                    onClick={() => handleSendToGenerator('', result.suggestions.suggestedBiomes)}
                                    className="text-[10px] font-bold text-strand-600 hover:text-strand-900 underline mt-2"
                                >
                                    Apply these Biomes to Generator
                                </button>
                             )}
                         </div>

                         {/* Themes */}
                         <div className="space-y-3">
                             <h4 className="text-xs font-bold text-strand-500 uppercase tracking-wider">Thematic Seeds</h4>
                             <ul className="space-y-2">
                                 {result.suggestions.thematicSeeds.map((theme, idx) => (
                                     <li key={idx} className="text-sm text-strand-600 italic font-serif border-l-2 border-strand-300 pl-2">
                                         {theme}
                                     </li>
                                 ))}
                             </ul>
                         </div>
                     </div>
                 </div>
             )}
         </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { DEFAULT_PARAMS, SEED_COUNTS, DEFAULT_AUTHOR_MIX } from './constants';
import {
  SeedGeneratorParams,
  AuthorMix,
  CalibrationMode,
  BookChapter,
  Seed,
  Snippet,
  VoiceAnalysisResult,
  BiomeType
} from './types';
import { generateStrandlineSeeds, generateVoiceProfile, remixStrandlineSeeds } from './services/geminiService';
import { SeedGeneratorForm } from './components/SeedGeneratorForm';
import { SeedResult } from './components/SeedResult';
import { VoiceLab } from './components/VoiceLab';
import { SeedExpander } from './components/SeedExpander';
import { ProseBuilder } from './components/ProseBuilder';
import { RevisionEngine } from './components/RevisionEngine';
import { ExportStudio } from './components/ExportStudio';
import { BookBuilder } from './components/BookBuilder';
import { ReferenceLibrary } from './components/ReferenceLibrary';
import { ArchiveBoxIcon, ArrowRightCircleIcon, SparklesIcon, PlusCircleIcon } from './components/Icons';

enum Tab {
  VoiceLab = 'Module A: Voice',
  Generator = 'Module B: Seeds',
  Expander = 'Module C: Expander',
  Prose = 'Module D: Prose',
  Revision = 'Module E: Revision',
  Export = 'Module F: Export',
  BookBuilder = 'Module G: Book Builder',
  Reference = 'Module H: Reference'
}

// --- Local Storage Helpers ---
const STORAGE_KEYS = {
  PARAMS: 'strandline_params',
  MIX: 'strandline_authorMix',
  SEEDS: 'strandline_seedBank',
  CHAPTERS: 'strandline_bookChapters',
  SNIPPETS: 'strandline_snippets',
  TAB: 'strandline_activeTab'
};

const loadJSON = <T,>(key: string, fallback: T): T => {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item) : fallback;
  } catch (e) {
    console.warn(`Failed to load ${key} from storage`);
    return fallback;
  }
};

function App() {
  // --- Persistent State Initialization ---

  // Active Tab
  const [activeTab, setActiveTab] = useState<Tab>(() => 
    loadJSON(STORAGE_KEYS.TAB, Tab.Generator)
  );

  // Generator Params (Merge with DEFAULT to ensure new fields are present if storage is old)
  const [params, setParams] = useState<SeedGeneratorParams>(() => {
    const saved = loadJSON(STORAGE_KEYS.PARAMS, {});
    return { ...DEFAULT_PARAMS, ...saved };
  });

  // Author Mix
  const [authorMix, setAuthorMix] = useState<AuthorMix>(() => 
    loadJSON(STORAGE_KEYS.MIX, DEFAULT_AUTHOR_MIX)
  );

  // Project Lists (The "To-Do" Lists of the writing project)
  const [seedBank, setSeedBank] = useState<Seed[]>(() => 
    loadJSON(STORAGE_KEYS.SEEDS, [])
  );
  const [bookChapters, setBookChapters] = useState<BookChapter[]>(() => 
    loadJSON(STORAGE_KEYS.CHAPTERS, [])
  );
  const [snippets, setSnippets] = useState<Snippet[]>(() => 
    loadJSON(STORAGE_KEYS.SNIPPETS, [])
  );

  // --- Transient State (Session only) ---
  const [generatedSeeds, setGeneratedSeeds] = useState<Seed[]>([]);
  const [selectedSeedIndices, setSelectedSeedIndices] = useState<number[]>([]);

  const [currentSeed, setCurrentSeed] = useState<string>('');
  const [currentExpansion, setCurrentExpansion] = useState<string>('');
  const [currentDraft, setCurrentDraft] = useState<string>('');
  const [currentRevision, setCurrentRevision] = useState<string>('');

  const [loading, setLoading] = useState(false);
  // Update labResult to hold the full object
  const [labResult, setLabResult] = useState<VoiceAnalysisResult | null>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  // --- Persistence Effects ---
  useEffect(() => localStorage.setItem(STORAGE_KEYS.TAB, JSON.stringify(activeTab)), [activeTab]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.PARAMS, JSON.stringify(params)), [params]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.MIX, JSON.stringify(authorMix)), [authorMix]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.SEEDS, JSON.stringify(seedBank)), [seedBank]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.CHAPTERS, JSON.stringify(bookChapters)), [bookChapters]);
  useEffect(() => localStorage.setItem(STORAGE_KEYS.SNIPPETS, JSON.stringify(snippets)), [snippets]);

  const handleInputChange = (field: keyof SeedGeneratorParams, value: any) => {
    setParams(prev => ({ ...prev, [field]: value }));
  };

  const handleGenerateSeeds = async () => {
    setLoading(true);
    setGeneratedSeeds([]);
    setSelectedSeedIndices([]);
    try {
      const seedsJsonString = await generateStrandlineSeeds(params, authorMix);
      const parsedSeeds: Seed[] = JSON.parse(seedsJsonString);
      setGeneratedSeeds(parsedSeeds);
      setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);
    } catch (error) {
      alert("Failed to generate seeds. Please ensure your API Key is valid.");
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateProfile = async (mode: CalibrationMode) => {
    setLoading(true);
    setLabResult(null);
    try {
       const result = await generateVoiceProfile(authorMix, mode);
       setLabResult(result);
    } catch (error) {
      alert("Failed to generate profile.");
    } finally {
      setLoading(false);
    }
  }

  const handleApplyVoiceContext = (location: string, biomes: BiomeType[]) => {
      // Update Params
      setParams(prev => ({
          ...prev,
          locationName: location || prev.locationName,
          biomeType: biomes.length > 0 ? biomes : prev.biomeType
      }));
      // Switch Tab
      setActiveTab(Tab.Generator);

      // Visual feedback
      setTimeout(() => alert(`Applied Context:\nLocation: ${location || "Unchanged"}\nBiomes: ${biomes.join(', ')}`), 100);
  }

  // Pipeline Handlers
  const handleUseSeed = (seed: Seed) => {
      // Format the seed object into a text block for the Expander
      const textBlock = `TITLE: ${seed.title}\nPREMISE: ${seed.premise}\nMOTIFS: ${seed.motifs.join(', ')}\nTONE: ${seed.toneProfile}\nSTRUCTURE: ${seed.structuralSuggestion}`;
      setCurrentSeed(textBlock);
      setActiveTab(Tab.Expander);
  };

  // --- GRAFTING / REMIX LOGIC ---
  const toggleSeedSelection = (index: number) => {
      setSelectedSeedIndices(prev => 
        prev.includes(index) 
            ? prev.filter(i => i !== index) 
            : [...prev, index]
      );
  };

  const handleRemixSeeds = async () => {
      const selectedSeeds = selectedSeedIndices.map(i => generatedSeeds[i]);
      if (selectedSeeds.length < 2) return;

      setLoading(true);
      try {
          const resultJson = await remixStrandlineSeeds(selectedSeeds, authorMix);
          const newSeeds: Seed[] = JSON.parse(resultJson);
          setGeneratedSeeds(prev => [...newSeeds, ...prev]); // Prepend new seeds
          setSelectedSeedIndices([]); // Reset selection
          setTimeout(() => {
             resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
          }, 100);
      } catch (e) {
          alert("Failed to graft seeds.");
      } finally {
          setLoading(false);
      }
  };

  const handleFuseSeeds = () => {
      const selectedSeeds = selectedSeedIndices.map(i => generatedSeeds[i]);
      if (selectedSeeds.length < 2) return;

      const combinedBlock = selectedSeeds.map((s, i) => `
[THREAD ${i + 1}]
TITLE: ${s.title}
PREMISE: ${s.premise}
MOTIFS: ${s.motifs.join(', ')}
TONE: ${s.toneProfile}
      `).join('\n\n');

      const fusionPrompt = `
COMBINED NARRATIVE INPUT (FUSED SEEDS):
The user wants to combine the following threads into a single expanded structure:

${combinedBlock}

INSTRUCTION: Weave these threads together into a single narrative arc.
      `;

      setCurrentSeed(fusionPrompt);
      setActiveTab(Tab.Expander);
      setSelectedSeedIndices([]);
  }

  const handleSaveToBank = (seed: Seed) => {
      setSeedBank(prev => [...prev, seed]);
      alert("Seed archived to Seed Bank.");
  };

  const handleRemoveFromBank = (index: number) => {
      const newBank = [...seedBank];
      newBank.splice(index, 1);
      setSeedBank(newBank);
  };

  const handleDownloadBank = () => {
      const timestamp = new Date().toISOString().slice(0, 10);
      const content = JSON.stringify(seedBank, null, 2);
      const blob = new Blob([content], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Strandline-SeedBank-${timestamp}.json`;
      a.click();
      URL.revokeObjectURL(url);
  };

  const handleAddToBook = (title: string, content: string) => {
    const newChapter: BookChapter = {
        id: Date.now().toString(),
        title,
        content,
        timestamp: Date.now(),
    };
    setBookChapters([...bookChapters, newChapter]);
    alert("Saved to Book Builder!");
  };

  const handleSaveSnippet = (text: string) => {
    const newSnippet: Snippet = {
        id: Date.now().toString(),
        content: text,
        source: activeTab === Tab.Prose ? 'Prose Builder' : 'Revision Engine',
        timestamp: Date.now()
    };
    setSnippets(prev => [...prev, newSnippet]);
  }

  const handleResetSession = () => {
    if (confirm("Reset the current writing session (clear editor)? Your Book Builder chapters, Seed Bank, and Settings will remain saved.")) {
        setCurrentSeed('');
        setCurrentExpansion('');
        setCurrentDraft('');
        setCurrentRevision('');
        setGeneratedSeeds([]);
        setSelectedSeedIndices([]);
        setActiveTab(Tab.Generator);
    }
