                                            </button>
                                            <button 
                                                onClick={() => handleSaveToBank(seed)}
                                                className="p-2 text-strand-500 hover:text-strand-800 hover:bg-strand-200 rounded-lg transition-colors"
                                                title="Save to Seed Bank"
                                            >
