  VOICE_PRESET_DETAILS, 
  NARRATOR_MODE_DETAILS, 
  STRUCTURE_MODE_DETAILS,
  JOURNEY_MODE_DETAILS
} from '../constants';
import { analyzeLocationWithSearch, analyzeRouteWithSearch, generateRandomScoutReport } from '../services/geminiService';
import { StyledSelect, StyledInput } from './InputGroup';
import { MultiSelect } from './MultiSelect';
import { 
    SparklesIcon, 
    RefreshIcon, 
    DiceIcon, 
    BookOpenIcon, 
    MapPinIcon, 
    SignalIcon, 
    MapIcon,
    PlusCircleIcon,
    TrashIcon
} from './Icons';

interface SeedGeneratorFormProps {
  params: SeedGeneratorParams;
  onParamChange: (field: keyof SeedGeneratorParams, value: any) => void;
  loading: boolean;
  onGenerate: () => void;
  onTabChange?: (tab: string) => void;
}

export const SeedGeneratorForm: React.FC<SeedGeneratorFormProps> = ({ params, onParamChange, loading, onGenerate, onTabChange }) => {

  const [grounding, setGrounding] = useState(false);
  const [groundingReport, setGroundingReport] = useState<string | null>(null);
  const [scoutingRandom, setScoutingRandom] = useState(false);

  // Local state for Waypoint Input
  const [newWaypoint, setNewWaypoint] = useState('');

  const handleSurpriseLocation = async () => {
    setScoutingRandom(true);
    setGroundingReport(null);
    onParamChange('groundingContext', '');

    try {
        const result = await generateRandomScoutReport(params.useRouteMode);

        if (params.useRouteMode) {
            onParamChange('startPoint', result.startPoint);
            onParamChange('endPoint', result.endPoint);
            onParamChange('waypoints', result.waypoints || []);
            onParamChange('groundingContext', result.routeDescription);
            setGroundingReport(result.routeDescription);
        } else {
            onParamChange('locationName', result.locationName);
            onParamChange('groundingContext', result.ecologicalReport);
            setGroundingReport(result.ecologicalReport);
            if (result.suggestedSeason) onParamChange('seasonalMode', result.suggestedSeason);
            if (result.suggestedWildlife) onParamChange('wildlifeFocus', result.suggestedWildlife);
        }

        // Common Enum Updates
        if (result.suggestedBiomes) onParamChange('biomeType', result.suggestedBiomes);
        if (result.suggestedWeather) onParamChange('weatherMode', result.suggestedWeather);

    } catch (e) {
        alert("Scout failed to return. Try again.");
    } finally {
        setScoutingRandom(false);
    }
  };

  const handleGrounding = async () => {
      // Toggle logic between Single Location and Route
      if (!params.useRouteMode) {
          if (!params.locationName) return;
          setGrounding(true);
          setGroundingReport(null);
          onParamChange('groundingContext', '');
          try {
              const result = await analyzeLocationWithSearch(params.locationName);
              if (result) {
                  updateFormParamsFromAnalysis(result);
              }
          } catch (e) {
              alert("Could not ground location. Please try again.");
          } finally {
              setGrounding(false);
          }
      } else {
          // Route Mode Analysis
          if (!params.startPoint || !params.endPoint) return;
          setGrounding(true);
          setGroundingReport(null);
          onParamChange('groundingContext', '');
          try {
              const result = await analyzeRouteWithSearch(params.startPoint, params.endPoint, params.waypoints || []);
              if (result) {
                  updateFormParamsFromAnalysis(result);
              }
          } catch (e) {
              alert("Could not scout route. Please try again.");
          } finally {
              setGrounding(false);
          }
      }
  }

  const updateFormParamsFromAnalysis = (result: any) => {
      if (result.suggestedBiomes && result.suggestedBiomes.length > 0) {
          onParamChange('biomeType', result.suggestedBiomes);
      }
      if (result.suggestedWeather && result.suggestedWeather.length > 0) {
          onParamChange('weatherMode', result.suggestedWeather);
      }
      if (result.suggestedSeason && result.suggestedSeason.length > 0) {
          onParamChange('seasonalMode', result.suggestedSeason);
      }
       if (result.suggestedWildlife && result.suggestedWildlife.length > 0) {
          onParamChange('wildlifeFocus', result.suggestedWildlife);
      }

      const report = result.ecologicalReport || result.routeDescription;
      if (report) {
          setGroundingReport(report);
          onParamChange('groundingContext', report);
      }
  }

  const addWaypoint = () => {
      if (newWaypoint.trim()) {
          const updated = [...(params.waypoints || []), newWaypoint.trim()];
          onParamChange('waypoints', updated);
          setNewWaypoint('');
      }
  }

  const removeWaypoint = (idx: number) => {
      const updated = [...(params.waypoints || [])];
      updated.splice(idx, 1);
      onParamChange('waypoints', updated);
  }

  const activeVoiceDetail = VOICE_PRESET_DETAILS[params.voicePreset];
  const lastActiveNarrator = params.narratorMode.length > 0 ? NARRATOR_MODE_DETAILS[params.narratorMode[params.narratorMode.length - 1]] : null;
  const lastActiveStructure = params.structureMode.length > 0 ? STRUCTURE_MODE_DETAILS[params.structureMode[params.structureMode.length - 1]] : null;
  const lastActiveJourney = params.journeyMode.length > 0 ? JOURNEY_MODE_DETAILS[params.journeyMode[params.journeyMode.length - 1]] : null;

  return (
    <div className="space-y-8">
      {/* Location & Environment */}
