export const planProseOutline = async (scaffold: string, mode: ProseGenerationParams['proseMode']): Promise<string[]> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });

    const prompt = `
You are the Strandline Structural Architect.
Based on the provided scaffold, breakdown the writing into 3-6 distinct, logical sections (headers).
The sections should represent the natural flow of the narrative.

SCAFFOLD:
"${scaffold}"

TARGET MODE: ${mode}

OUTPUT:
Return a JSON object with a "sections" key containing an array of section header strings.
