import { GoogleGenAI, Type, Schema } from "@google/genai";
import { 
  SeedGeneratorParams, 
  AuthorMix, 
  CalibrationMode, 
  VoicePreset, 
  SeedExpansionParams, 
  ProseGenerationParams, 
  RevisionParams, 
  BookChapter, 
  ProseStructure,
  ExpansionDepth, 
  ExpansionLength, 
  ExpansionFormat, 
  ExpansionMode, 
  BiomeType, 
  WeatherMode, 
  SeasonalMode, 
  WildlifeFocus, 
  RevisionFocus, 
  Seed, 
  VoiceAnalysisResult,
  JourneyMode
} from "../types";
import { AUTHOR_DEFINITIONS, VOICE_PRESET_DETAILS } from "../constants";

const GEMINI_MODEL = "gemini-3-pro-preview";

const getApiKey = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables.");
  }
  return apiKey;
};

// --- Helper to build mix string ---
const formatMixPrompt = (mix: AuthorMix): string => {
  const activeAuthors = AUTHOR_DEFINITIONS
    .map(def => ({ ...def, val: mix[def.id] }))
    .filter(a => a.val > 0);

  if (activeAuthors.length === 0) return "Standard Strandline Tone (No specific author bias).";

  return activeAuthors
    .map(a => `${a.name}: ${a.val}% influence (${a.traits})`)
    .join('\n');
};

// --- MODULE B: SEED GENERATOR ---
export const generateStrandlineSeeds = async (params: SeedGeneratorParams, customMix?: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  let voiceInstructions = "";

  if (params.voicePreset === VoicePreset.CustomCalibration && customMix) {
    voiceInstructions = `
STRANDLINE AUTHOR VOICE ENGINE (CUSTOM CALIBRATION):
The user has configured a custom mixing desk. Blend the following authors with the specified intensity (0-100):

${formatMixPrompt(customMix)}

INSTRUCTIONS:
Synthesize these specific inputs into a coherent voice.
• High intensity (70-100%): Dominant stylistic features, sentence structure, and worldview.
• Medium intensity (30-60%): Frequent tonal coloring, specific vocabulary, and pacing.
• Low intensity (1-25%): Subtle flavor, occasional motifs, or specific observational habits.
    `;
  } else {
    // Standard Presets Logic
    const details = VOICE_PRESET_DETAILS[params.voicePreset];
    const presetDesc = details 
      ? `\nPRESET DEFINITION:\nAUTHORS: ${details.authors}\nKEYWORDS: ${details.keywords}\nEFFECTS: ${details.effects}` 
      : "";

    voiceInstructions = `
STRANDLINE AUTHOR VOICE ENGINE:
The user has selected the '${params.voicePreset}' voice.
Blend the influences of the authors associated with the selected Voice Preset ONLY as tonal gravity and rhythm.${presetDesc}
    `;
  }

  // Format Array Params for Prompt
  const formatArray = (val: string | string[]) => Array.isArray(val) ? val.join(' + ') : val;

  // Construct Geography Context based on Mode
  let geographyContext = "";
  let routeInstructions = "";

  if (params.useRouteMode) {
      const stops = params.waypoints && params.waypoints.length > 0 ? ` via [${params.waypoints.join(', ')}]` : '';
      const contextInjection = params.groundingContext 
        ? `\nREAL-WORLD ROUTE DESCRIPTION: ${params.groundingContext}\nINSTRUCTION: Ensure the narrative reflects these specific changing environments.` 
        : '';

      geographyContext = `
JOURNEY ROUTE: From "${params.startPoint}" to "${params.endPoint}"${stops}.
MODE: LINEAR TRAVERSE (Moving through changing biomes).${contextInjection}
      `;
      routeInstructions = `
CRITICAL INSTRUCTION ON ROUTE INTEGRITY:
The user has defined a specific LINEAR JOURNEY from "${params.startPoint}" to "${params.endPoint}".
The generated seeds MUST encapsulate the FULL ARC of this journey.
- Do NOT generate a seed about just one spot along the way.
- The 'Premise' must explicitly frame the text as a travelogue covering the entire distance (A -> B).
- The 'Structural Suggestion' must explicitly map the chapters from the Starting Location, through the Transition Zones/Waypoints, to the Destination.
- Account for the change in geology/biome/atmosphere as the narrator moves from Start to End.
- Negative Constraint: Do not write a static vignette. This is a dynamic traverse.
      `;
  } else {
      const contextInjection = params.groundingContext 
        ? `\nREAL-WORLD ECOLOGICAL CONTEXT: ${params.groundingContext}` 
        : '';
      geographyContext = `
LOCATION: ${params.locationName || "Unknown Location"}
MODE: GENIUS LOCI (Deep dive into a single place).${contextInjection}
      `;
  }

  const prompt = `
Generate ${params.seedCount} high-quality Strandline-style narrative seeds.

VARIABLES:
${geographyContext}
BIOME: ${formatArray(params.biomeType)}
WEATHER MODE: ${formatArray(params.weatherMode)}
SEASON: ${formatArray(params.seasonalMode)}
WILDLIFE FOCUS: ${formatArray(params.wildlifeFocus)}
VOICE PRESET: ${params.voicePreset}
NARRATOR MODE: ${formatArray(params.narratorMode)}
JOURNEY SCALE: ${params.journeyScale}
JOURNEY MODE: ${formatArray(params.journeyMode)}
STRUCTURE MODE: ${formatArray(params.structureMode)}

${voiceInstructions}

Do NOT mention the authors in the written output.
Let their presence be inferred through pacing, imagery, depth of ecological noticing, mythic atmosphere, and sensory anchoring.

CRITICAL INSTRUCTION ON JOURNEY MODE:
The selected JOURNEY MODE (${formatArray(params.journeyMode)}) must physically dictate the narrative perspective:
- If 'Paddle' or 'Kayak': Perspective must be water-level, rhythmic, silent, and vulnerable to tides/currents.
- If 'Foot' or 'Hike': Perspective must be tactile, ground-level, slower-paced, and physically exerting.
- If 'Road' or 'Rail': Perspective must be framed by windows, transient, moving through contrasting zones rapidly, detached yet observant.
- If 'Sail': Perspective must be dictated by wind, charts, and the mechanics of the vessel.
- If 'Stationary': Perspective must be deep, time-lapse observation of a single point changing over time.
- If 'Swim': Perspective must be immersive, cold, fluid, and bodily.
- If 'Dive' or 'Snorkel': Perspective must be submarine, weightless, breath-focused, and alien.

${routeInstructions}

REQUIREMENTS:
• Strong specificity to LOCATION + BIOME.
• Weather and wildlife integral, not decorative.
• Voice consistent with selected preset or mix.
• The 'PREMISE' must be SUBSTANTIAL (3-5 sentences). It should detail the specific atmospheric pressure, the immediate ecological conflict, and the narrator's internal state. Avoid brief summaries; provide a dense, texture-rich narrative opening.
• The 'PREMISE' must explicitly reflect the mode of travel.
• The 'STRUCTURAL SUGGESTION' must reflect the pacing of the journey.
• No generic filler.
• Seeds must feel like “the beginning of a Strandline book.”

OUTPUT FORMAT:
Return a JSON object containing an array of seeds under the key "seeds".
`;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        temperature: 0.85,
        topP: 0.95,
        maxOutputTokens: 8192,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            seeds: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  premise: { type: Type.STRING },
                  motifs: { type: Type.ARRAY, items: { type: Type.STRING } },
                  toneProfile: { type: Type.STRING },
                  structuralSuggestion: { type: Type.STRING }
                },
                required: ["title", "premise", "motifs", "toneProfile", "structuralSuggestion"]
              }
            }
          },
          required: ["seeds"]
        }
      }
    });

    const json = JSON.parse(response.text || "{\"seeds\": []}");
    return JSON.stringify(json.seeds || []);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

// --- MODULE B (EXTENSION): REMIXER ---
export const remixStrandlineSeeds = async (seeds: Seed[], mix: AuthorMix): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });
    const voiceInstruction = formatMixPrompt(mix);

    // Format input seeds for the prompt
    const seedContext = seeds.map((s, i) => `
PARENT SEED ${i + 1}:
Title: ${s.title}
Premise: ${s.premise}
Motifs: ${s.motifs.join(', ')}
    `).join('\n');

    const prompt = `
You are the Strandline Grafting Engine.
Your task is to take ${seeds.length} distinct narrative seeds and "GRAFT" them together to create 3 NEW, HYBRID seeds.

PARENT MATERIAL:
${seedContext}

VOICE PROFILE:
${voiceInstruction}

INSTRUCTIONS:
1. Identify the core conflict or atmospheric pressure in each Parent Seed.
2. SYNTHESIZE these elements. Do not just list them side-by-side. Create a new narrative that requires BOTH elements to exist.
   - Example: If Parent A is "Coastal Ghost Story" and Parent B is "Industrial Rail Journey", the Child should be "A ghost story about a haunted rail line running along a collapsing coast."
3. Resolve any contradictions (e.g., Desert vs Arctic) by creating a "Transition Zone" or a "Surreal Climate Shift".
4. Generate 3 distinct "Child" seeds based on this synthesis. 
5. The 'Premise' for each child seed must be detailed (3-5 sentences), exploring the specific friction between the grafted elements.

OUTPUT FORMAT:
Return a JSON object containing an array of seeds under the key "seeds".
    `;

    try {
        const response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                temperature: 0.9,
                maxOutputTokens: 8192,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        seeds: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    title: { type: Type.STRING },
                                    premise: { type: Type.STRING },
                                    motifs: { type: Type.ARRAY, items: { type: Type.STRING } },
                                    toneProfile: { type: Type.STRING },
                                    structuralSuggestion: { type: Type.STRING }
                                },
                                required: ["title", "premise", "motifs", "toneProfile", "structuralSuggestion"]
                            }
                        }
                    },
                    required: ["seeds"]
                }
            }
        });
        const json = JSON.parse(response.text || "{\"seeds\": []}");
        return JSON.stringify(json.seeds || []);
    } catch (error) {
        console.error("Remix Error:", error);
        throw error;
    }
}

