// --- RANDOM SCOUT (AI-ORGANIC SURPRISE ME) ---
export const generateRandomScoutReport = async (useRouteMode: boolean, journeyModes: JourneyMode[] = []): Promise<any> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const modeContext = useRouteMode 
    ? "MODE: LINEAR ROUTE (A journey from Point A to Point B)" 
    : "MODE: SINGLE LOCUS (A specific, deeply textured place)";

  // New logic for Journey Mode constraints
  let journeyConstraint = "";
  // Filter out Unspecified to see if we have specific constraints
  const specificModes = journeyModes.filter(m => m !== JourneyMode.Unspecified);

  if (specificModes.length > 0) {
      journeyConstraint = `
CRITICAL CONSTRAINT - JOURNEY MODE:
The user has pre-selected the following travel mode(s): ${specificModes.join(', ')}.
The generated location or route MUST be perfectly suited for this specific mode of travel.
- If 'Rail': It must be a railway line, station, or corridor.
- If 'Sail', 'Paddle', 'Swim', 'Dive': It must be a water-based location (river, sea, lake, canal).
- If 'Road': It must be a highway, backroad, or track.
- If 'Foot': It must be a trail, path, or walkable terrain.
      `;
  }

  const prompt = `
  You are the Strandline Scout.
  Generate a completely RANDOM, chemically complex, high-contrast location or route on Earth that fits the 'Strandline' aesthetic.

  AESTHETIC CRITERIA:
  - Liminal spaces (borders, edges, coastlines).
  - Deep time resonance (geology, ruins, fossils).
  - Ecological recovery or strangeness.
  - Avoid generic tourist spots. Look for the overlooked, the specific, the haunted.

  ${modeContext}
  ${journeyConstraint}

  AVAILABLE ENUMS:
  Biomes: ${Object.values(BiomeType).join(', ')}
  Weather: ${Object.values(WeatherMode).join(', ')}
