                    }
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) {
        console.error("Field Guide Error:", error);
        return { flora: [], fauna: [], phenomena: [] };
    }
}

// --- MODULE G: BOOK BUILDER ---
export const generateBookMeta = async (chapters: BookChapter[], mix: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);

  const chapterSummary = chapters.map((c, i) => `CHAPTER ${i + 1}: ${c.title}\n${c.content.substring(0, 300)}...`).join('\n\n');

  const prompt = `
You are the Strandline Book Architect (Module G).
The user has assembled the following chapters for a book.

VOICE PROFILE (Active Mix):
${voiceInstruction}

CHAPTER PREVIEWS:
${chapterSummary}

TASK:
1. Suggest a TITLE for this book that fits the Strandline aesthetic.
2. Write a 200-word SYNOPSIS of the work.
3. Identify 3 THEMATIC THREADS that run through these chapters.
4. Suggest what is missing—what should the next chapter be?

OUTPUT:
A structured analysis of the manuscript so far.
`;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { temperature: 0.7 }
    });
    return response.text || "No metadata generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

