export async function* generateProseSectionStream(
    params: ProseGenerationParams, 
    mix: AuthorMix, 
    sectionTitle: string, 
    previousContext: string
): AsyncGenerator<string, void, unknown> {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);
  const prompt = `Write section "${sectionTitle}" based on scaffold: ${params.scaffoldText}. Voice: ${voiceInstruction}.`;
  try {
    const response = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { temperature: 0.85 }
    });
    for await (const chunk of response) {
        if (chunk.text) {
            yield chunk.text;
        }
    }
  } catch (error) {
    throw error;
  }
}

