    Seasons: ${Object.values(SeasonalMode).join(', ')}
    Wildlife: ${Object.values(WildlifeFocus).join(', ')}`;

    try {
      const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: prompt,
        config: {
