  const prompt = `Generate full prose for scaffold: ${params.scaffoldText}. Voice: ${voiceInstruction}.`;
  try {
    const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { temperature: 0.85 } 
    });
    let fullText = "";
    for await (const chunk of responseStream) {
        if (chunk.text) {
