  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const voiceInstruction = formatMixPrompt(mix);
  const prompt = `Revise this draft: "${params.draftText}". Voice: ${voiceInstruction}. Focus: ${params.revisionFocus}.`;
  try {
    const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { temperature: 0.7 }
    });
    let fullText = "";
    for await (const chunk of responseStream) {
        if (chunk.text) {
            fullText += chunk.text;
        }
    }
    return fullText;
  } catch (error) {
    throw error;
  }
};

export const generateEcologicalPalette = async (biomes: BiomeType[], seasons: SeasonalMode[]): Promise<any> => {
    const ai = new GoogleGenAI({ apiKey: getApiKey() });
    const prompt = `Generate ecological palette for biomes: ${biomes.join(', ')}.`;
    try {
        const response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                responseMimeType: "application/json"
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) {
        return { flora: [], fauna: [], phenomena: [] };
    }
}

export const generateBookMeta = async (chapters: BookChapter[], mix: AuthorMix): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });
  const mixDescription = formatMixPrompt(mix);
  const prompt = `Analyze these chapters: ${chapters.length}. Voice: ${mixDescription}. Suggest title and synopsis.`;
  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { temperature: 0.7 }
    });
    return response.text || "";
  } catch (error) {
    throw error;
  }
};

