import React, { useState } from 'react';
import { 
  SeedGeneratorParams, 
  BiomeType, 
  WeatherMode, 
  SeasonalMode, 
  WildlifeFocus, 
  VoicePreset, 
  NarratorMode, 
  JourneyScale, 
  JourneyMode, 
  StructureMode,
  NarrativeAnchor
} from '../types';
import { 
  SEED_COUNTS, 
  VOICE_PRESET_DETAILS, 
  NARRATOR_MODE_DETAILS, 
  STRUCTURE_MODE_DETAILS,
  JOURNEY_MODE_DETAILS
} from '../constants';
import { 
  analyzeLocationWithSearch, 
  analyzeRouteWithSearch, 
  generateRandomScoutReport,
  suggestRouteFromLocation 
} from '../services/geminiService';
import { StyledSelect, StyledInput } from './InputGroup';
import { MultiSelect } from './MultiSelect';
import { 
    SparklesIcon, 
    RefreshIcon, 
    DiceIcon, 
    BookOpenIcon, 
    MapPinIcon, 
    SignalIcon, 
    MapIcon,
    PlusCircleIcon,
    TrashIcon,
    ArrowRightCircleIcon
} from './Icons';

interface SeedGeneratorFormProps {
  params: SeedGeneratorParams;
  onParamChange: (field: keyof SeedGeneratorParams, value: any) => void;
  loading: boolean;
  onGenerate: () => void;
  onTabChange?: (tab: string) => void;
}

export const SeedGeneratorForm: React.FC<SeedGeneratorFormProps> = ({ params, onParamChange, loading, onGenerate, onTabChange }) => {

  const [grounding, setGrounding] = useState(false);
  const [routeSuggesting, setRouteSuggesting] = useState(false);
  const [groundingReport, setGroundingReport] = useState<string | null>(null);
  const [groundingSources, setGroundingSources] = useState<any[]>([]);
  const [scoutingRandom, setScoutingRandom] = useState(false);
  const [newWaypoint, setNewWaypoint] = useState('');

  const handleSurpriseLocation = async () => {
    setScoutingRandom(true);
    setGroundingReport(null);
    setGroundingSources([]);
    onParamChange('groundingContext', '');

    try {
        const result = await generateRandomScoutReport(params.useRouteMode, params.journeyMode);

        if (params.useRouteMode) {
            onParamChange('startPoint', result.startPoint);
            onParamChange('endPoint', result.endPoint);
            onParamChange('waypoints', result.waypoints || []);
            onParamChange('groundingContext', result.routeDescription);
            setGroundingReport(result.routeDescription);
        } else {
            onParamChange('locationName', result.locationName);
            onParamChange('groundingContext', result.ecologicalReport);
            setGroundingReport(result.ecologicalReport);
            if (result.suggestedSeason) onParamChange('seasonalMode', result.suggestedSeason);
            if (result.suggestedWildlife) onParamChange('wildlifeFocus', result.suggestedWildlife);
        }

        if (result.suggestedBiomes) onParamChange('biomeType', result.suggestedBiomes);
        if (result.suggestedWeather) onParamChange('weatherMode', result.suggestedWeather);
        if (result.sources) setGroundingSources(result.sources);

    } catch (e) {
        console.error("Scout failed", e);
        alert("Scout failed to return real-world data. Try again.");
    } finally {
        setScoutingRandom(false);
    }
  };

  const handleSuggestRoute = async (sourceLocation: string) => {
      if (!sourceLocation) return;
      setRouteSuggesting(true);
      setGroundingReport(null);
      setGroundingSources([]);

      try {
          const result = await suggestRouteFromLocation(sourceLocation);
          if (result && !result.error) {
              onParamChange('useRouteMode', true);
              onParamChange('startPoint', result.startPoint);
              onParamChange('endPoint', result.endPoint);
              onParamChange('waypoints', result.waypoints || []);
              onParamChange('biomeType', result.suggestedBiomes || params.biomeType);
              onParamChange('groundingContext', result.routeDescription);
              setGroundingReport(result.routeDescription);
              setGroundingSources(result.sources || []);
          } else {
              alert("Could not suggest a logical route from this location.");
          }
      } catch (e) {
          alert("Error scouting route.");
      } finally {
          setRouteSuggesting(false);
      }
  }

  const handleGrounding = async () => {
      setGroundingReport(null);
      setGroundingSources([]);

      if (!params.useRouteMode) {
          if (!params.locationName) return;
          setGrounding(true);
          try {
              const result = await analyzeLocationWithSearch(params.locationName);
              if (result && !result.error) {
                  updateFormParamsFromAnalysis(result);
              } else {
                  alert(`Scout could not find specific ecological details for "${params.locationName}". Try a more specific place name.`);
              }
          } catch (e) {
              alert("Could not ground location.");
          } finally {
              setGrounding(false);
          }
      } else {
          if (!params.startPoint || !params.endPoint) return;
          setGrounding(true);
          try {
              const result = await analyzeRouteWithSearch(params.startPoint, params.endPoint, params.waypoints || []);
              if (result) updateFormParamsFromAnalysis(result);
          } catch (e) {
              alert("Could not scout route.");
          } finally {
              setGrounding(false);
          }
      }
  }

  const updateFormParamsFromAnalysis = (result: any) => {
      if (result.suggestedBiomes?.length > 0) onParamChange('biomeType', result.suggestedBiomes);
      if (result.suggestedWeather?.length > 0) onParamChange('weatherMode', result.suggestedWeather);
      if (result.suggestedSeason?.length > 0) onParamChange('seasonalMode', result.suggestedSeason);
      if (result.suggestedWildlife?.length > 0) onParamChange('wildlifeFocus', result.suggestedWildlife);

      const report = result.ecologicalReport || result.routeDescription;
      if (report) {
          setGroundingReport(report);
          onParamChange('groundingContext', report);
      }

      if (result.sources) {
          setGroundingSources(result.sources);
      }
  }

  const addWaypoint = () => {
      if (newWaypoint.trim()) {
          const updated = [...(params.waypoints || []), newWaypoint.trim()];
          onParamChange('waypoints', updated);
          setNewWaypoint('');
      }
  }

  const removeWaypoint = (idx: number) => {
      const updated = [...(params.waypoints || [])];
      updated.splice(idx, 1);
      onParamChange('waypoints', updated);
  }

  const activeVoiceDetail = VOICE_PRESET_DETAILS[params.voicePreset];
  const lastActiveNarrator = params.narratorMode.length > 0 ? NARRATOR_MODE_DETAILS[params.narratorMode[params.narratorMode.length - 1]] : null;
  const lastActiveStructure = params.structureMode.length > 0 ? STRUCTURE_MODE_DETAILS[params.structureMode[params.structureMode.length - 1]] : null;
  const lastActiveJourney = params.journeyMode.length > 0 ? JOURNEY_MODE_DETAILS[params.journeyMode[params.journeyMode.length - 1]] : null;

  return (
    <div className="space-y-8">
      {/* NARRATIVE ANCHOR PIVOT */}
      <div className="bg-strand-100 rounded-xl p-4 border border-strand-200 shadow-sm">
        <label className="text-xs font-bold text-strand-500 uppercase tracking-widest block mb-3 text-center">Narrative Anchor (Lead Focus)</label>
        <div className="flex flex-wrap gap-2 justify-center">
             {Object.values(NarrativeAnchor).map((anchor) => (
                <button
                    key={anchor}
                    onClick={() => onParamChange('narrativeAnchor', anchor)}
                    className={`px-4 py-2 rounded-lg text-xs font-bold transition-all border ${params.narrativeAnchor === anchor ? 'bg-strand-800 text-white border-strand-800 shadow-md' : 'bg-white text-strand-500 border-strand-200 hover:border-strand-400'}`}
                >
                    {anchor}
                </button>
             ))}
        </div>
        <p className="text-[10px] text-strand-500 text-center mt-3 px-4 leading-relaxed">
            {params.narrativeAnchor === NarrativeAnchor.Place && "Centers the story on the human traveler's path and encounter."}
            {params.narrativeAnchor === NarrativeAnchor.Species && "Centers the story on the life cycle and sensory world of a specific organism."}
            {params.narrativeAnchor === NarrativeAnchor.Biome && "Centers the story on the metabolism and energy cycles of the ecosystem."}
        </p>
      </div>

      {/* Location & Environment */}
      <div className="space-y-4">
        <h3 className="font-serif text-lg text-strand-800 border-b border-strand-100 pb-2 mb-4">Location & Focal Point</h3>

        {/* Mode Toggle */}
        <div className="flex gap-4 mb-4">
             <button 
                onClick={() => { onParamChange('useRouteMode', false); setGroundingReport(null); setGroundingSources([]); onParamChange('groundingContext', ''); }}
                className={`flex items-center gap-2 px-3 py-2 rounded-md text-sm font-semibold transition-colors ${!params.useRouteMode ? 'bg-strand-700 text-white' : 'bg-strand-100 text-strand-500 hover:bg-strand-200'}`}
             >
                 <MapPinIcon className="w-4 h-4" />
                 Single Location
             </button>
             <button 
                onClick={() => { onParamChange('useRouteMode', true); setGroundingReport(null); setGroundingSources([]); onParamChange('groundingContext', ''); }}
                className={`flex items-center gap-2 px-3 py-2 rounded-md text-sm font-semibold transition-colors ${params.useRouteMode ? 'bg-strand-700 text-white' : 'bg-strand-100 text-strand-500 hover:bg-strand-200'}`}
             >
                 <MapIcon className="w-4 h-4" />
                 Linear Journey / Route
             </button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-5">
          {/* Dynamic Location Input Area */}
          <div className="flex flex-col gap-1.5 sm:col-span-1">
             {!params.useRouteMode ? (
                 <>
                    <div className="flex justify-between items-baseline pl-1">
                        <label className="text-xs font-semibold text-strand-500 uppercase tracking-wider">
                            Location Name
                        </label>
                        <div className="flex gap-2">
                            <button 
                                type="button" 
                                onClick={handleSurpriseLocation}
                                disabled={scoutingRandom}
                                className="text-[10px] text-strand-400 hover:text-strand-700 font-medium flex items-center gap-1 transition-colors"
                            >
                                {scoutingRandom ? <RefreshIcon className="w-3 h-3 animate-spin" /> : <DiceIcon className="w-3 h-3" />}
                                {scoutingRandom ? 'Scouting...' : 'Surprise Me'}
                            </button>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <input
                            value={params.locationName}
                            onChange={(e) => onParamChange('locationName', e.target.value)}
                            placeholder="e.g. The Lost Coast"
                            className="w-full bg-white border border-strand-300 text-strand-800 text-sm rounded-md p-3 focus:outline-none focus:ring-2 focus:ring-strand-400 focus:border-transparent transition-shadow placeholder-strand-300"
                        />
                        <button
                            onClick={handleGrounding}
                            disabled={grounding || !params.locationName}
                            title="Ground Location using Google Search"
                            className={`flex items-center justify-center p-3 rounded-md border transition-all ${grounding ? 'bg-strand-100 border-strand-200 text-strand-400' : 'bg-white border-strand-300 text-strand-600 hover:bg-strand-50 shadow-sm'}`}
                        >
                            {grounding ? <RefreshIcon className="w-5 h-5 animate-spin" /> : <MapPinIcon className="w-5 h-5" />}
                        </button>
                    </div>
                    {params.locationName && (
                        <button 
                            onClick={() => handleSuggestRoute(params.locationName)}
                            disabled={routeSuggesting}
                            className="text-[10px] font-bold text-strand-600 hover:text-strand-900 flex items-center gap-1 mt-1 transition-colors group"
                        >
                            {routeSuggesting ? <RefreshIcon className="w-3 h-3 animate-spin" /> : <SparklesIcon className="w-3 h-3 group-hover:scale-110 transition-transform" />}
                            {routeSuggesting ? 'Scouting Paths...' : 'Expand to Journey (Suggest Route)'}
                        </button>
                    )}
                 </>
             ) : (
                 <div className="space-y-3 bg-strand-50 p-3 rounded-lg border border-strand-200">
                     <div className="flex justify-between items-baseline pl-1">
                        <label className="text-xs font-semibold text-strand-500 uppercase tracking-wider">Route Plan</label>
                        <button type="button" onClick={handleSurpriseLocation} disabled={scoutingRandom} className="text-[10px] text-strand-400 hover:text-strand-700 font-medium flex items-center gap-1 transition-colors">
                             {scoutingRandom ? <RefreshIcon className="w-3 h-3 animate-spin" /> : <DiceIcon className="w-3 h-3" />}
                             {scoutingRandom ? 'Scouting...' : 'Random Route'}
                        </button>
                    </div>
                     <div className="space-y-1.5">
                        <label className="text-[10px] font-bold text-strand-400 uppercase tracking-widest pl-1">Start</label>
                        <div className="flex gap-2">
                             <input 
                                value={params.startPoint || ''} 
                                onChange={(e) => onParamChange('startPoint', e.target.value)} 
                                placeholder="e.g. London"
                                className="w-full bg-white border border-strand-300 text-sm rounded-md p-2 focus:ring-1 focus:ring-strand-400 focus:outline-none"
                             />
                             {params.startPoint && (
                                <button 
                                    onClick={() => handleSuggestRoute(params.startPoint || '')}
                                    disabled={routeSuggesting}
                                    title="Suggest Destination & Waypoints"
                                    className={`p-2 rounded border transition-all ${routeSuggesting ? 'bg-strand-100 text-strand-300' : 'bg-white border-strand-300 text-strand-600 hover:bg-strand-100 shadow-sm'}`}
                                >
                                    {routeSuggesting ? <RefreshIcon className="w-4 h-4 animate-spin" /> : <SparklesIcon className="w-4 h-4" />}
                                </button>
                             )}
                        </div>
                     </div>
                     <div className="flex flex-col gap-1.5">
                        <label className="text-xs font-semibold text-strand-500 uppercase tracking-wider pl-1">Waypoints</label>
                        <div className="flex gap-2">
                            <input value={newWaypoint} onChange={(e) => setNewWaypoint(e.target.value)} placeholder="Add stop..." className="w-full bg-white border border-strand-300 text-xs rounded-md p-2" />
                            <button onClick={addWaypoint} className="text-strand-600 hover:text-strand-900 p-2"><PlusCircleIcon className="w-5 h-5" /></button>
                        </div>
                        {params.waypoints?.length > 0 && (
                            <div className="space-y-1 mt-1">
                                {params.waypoints.map((wp, idx) => (
                                    <div key={idx} className="flex justify-between items-center bg-white px-2 py-1 rounded border border-strand-200 text-xs">
                                        <span className="truncate text-strand-700">{wp}</span>
                                        <button onClick={() => removeWaypoint(idx)} className="text-red-300 hover:text-red-500"><TrashIcon className="w-3 h-3" /></button>
                                    </div>
                                ))}
                            </div>
                        )}
                     </div>
                     <StyledInput label="End" placeholder="e.g. Canterbury" value={params.endPoint || ''} onChange={(e) => onParamChange('endPoint', e.target.value)} />
                 </div>
             )}
          </div>

          <div className="flex flex-col gap-1.5">
              <MultiSelect label="Primary Biome" options={Object.values(BiomeType)} value={params.biomeType} onChange={(val) => onParamChange('biomeType', val)} maxSelections={3} />
              {params.narrativeAnchor === NarrativeAnchor.Biome && (
                  <div className="bg-strand-800 text-white p-2 rounded text-[10px] animate-pulse">
                      <strong>Biome Lead:</strong> Narrative will center on the systemic metabolism of these environments.
                  </div>
              )}
          </div>

          <div className="flex flex-col gap-1.5">
             <StyledInput label="Focal Species (Optional)" placeholder="e.g. Curlew, Fungi, Grey Seal" value={params.focalSpecies || ''} onChange={(e) => onParamChange('focalSpecies', e.target.value)} />
             {params.narrativeAnchor === NarrativeAnchor.Species && (
                 <div className="bg-strand-800 text-white p-2 rounded text-[10px] animate-pulse">
                    <strong>Species Lead:</strong> Narrative will center on the sensory world (Umwelt) of this organism.
                 </div>
             )}
          </div>
        </div>

        {groundingReport && (
            <div className="bg-green-50 border border-green-100 rounded-lg p-3 space-y-3 animate-in fade-in slide-in-from-top-2">
                <div className="flex gap-3 items-start">
                    <SignalIcon className="w-4 h-4 text-green-600 mt-0.5 flex-shrink-0" />
                    <div className="text-xs text-green-800 leading-relaxed">
                        <strong className="uppercase tracking-wide text-[10px] text-green-600 block mb-1">
                            {params.useRouteMode ? 'Route Analysis Applied' : 'Ecological Data Applied'}
                        </strong>
                        {groundingReport}
                    </div>
                </div>

                {groundingSources.length > 0 && (
                    <div className="pt-2 border-t border-green-200">
                        <span className="text-[9px] font-bold text-green-600 uppercase tracking-widest block mb-1">Search Sources:</span>
                        <div className="flex flex-wrap gap-2">
                            {groundingSources.map((source, idx) => (
                                <a 
                                    key={idx} 
                                    href={source.uri} 
                                    target="_blank" 
                                    rel="noopener noreferrer"
                                    className="text-[9px] text-green-700 bg-green-100 hover:bg-green-200 px-2 py-0.5 rounded border border-green-200 flex items-center gap-1 transition-colors"
                                >
                                    <ArrowRightCircleIcon className="w-2 h-2" />
                                    {source.title || "Source"}
                                </a>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        )}

      </div>

      {/* Weather & Season */}
      <div className="space-y-4">
        <h3 className="font-serif text-lg text-strand-800 border-b border-strand-100 pb-2 mb-4">Weather & Season</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
          <MultiSelect label="Weather Mode" options={Object.values(WeatherMode)} value={params.weatherMode} onChange={(val) => onParamChange('weatherMode', val)} maxSelections={3} />
          <MultiSelect label="Seasonal Mode" options={Object.values(SeasonalMode)} value={params.seasonalMode} onChange={(val) => onParamChange('seasonalMode', val)} maxSelections={3} />
        </div>
      </div>

      {/* Wildlife & Voice */}
      <div className="space-y-4">
        <div className="flex justify-between items-end border-b border-strand-100 pb-2 mb-4">
            <h3 className="font-serif text-lg text-strand-800">Wildlife & Voice</h3>
            {onTabChange && (
                <button onClick={() => onTabChange('Reference')} className="flex items-center gap-1 text-[10px] text-strand-500 hover:text-strand-800 uppercase tracking-wide font-bold transition-colors">
                    <BookOpenIcon className="w-3 h-3" />
                    View Full Reference
                </button>
            )}
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-5">
          <MultiSelect label="Wildlife Focus" options={Object.values(WildlifeFocus)} value={params.wildlifeFocus} onChange={(val) => onParamChange('wildlifeFocus', val)} maxSelections={3} />
          <div className="flex flex-col gap-1.5">
              <StyledSelect label="Voice Preset" options={Object.values(VoicePreset)} value={params.voicePreset} onChange={(e) => onParamChange('voicePreset', e.target.value)} />
              {activeVoiceDetail && (
                <div className="bg-strand-50 border border-strand-100 p-2 rounded text-[10px] text-strand-600 space-y-1">
                   <div><span className="font-bold text-strand-700">Keywords:</span> {activeVoiceDetail.keywords}</div>
                   <div className="italic text-strand-500 border-l-2 border-strand-200 pl-1">"{activeVoiceDetail.effects}"</div>
                </div>
              )}
          </div>
          <div className="flex flex-col gap-1.5">
            <MultiSelect label="Narrator Mode" options={Object.values(NarratorMode)} value={params.narratorMode} onChange={(val) => onParamChange('narratorMode', val)} maxSelections={3} />
            {lastActiveNarrator && (
                 <div className="bg-strand-50 border border-strand-100 p-2 rounded text-[10px] text-strand-600 leading-tight">
                    <span className="font-bold text-strand-700">Perspective: </span> {lastActiveNarrator}
                 </div>
             )}
          </div>
        </div>
      </div>

      {/* Scale & Structure */}
      <div className="space-y-4">
        <h3 className="font-serif text-lg text-strand-800 border-b border-strand-100 pb-2 mb-4">Scale & Structure</h3>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-5">
          <StyledSelect label="Journey Scale" options={Object.values(JourneyScale)} value={params.journeyScale} onChange={(e) => onParamChange('journeyScale', e.target.value)} />
          <div className="flex flex-col gap-1.5">
            <MultiSelect label="Structure Mode" options={Object.values(StructureMode)} value={params.structureMode} onChange={(val) => onParamChange('structureMode', val)} maxSelections={2} />
            {lastActiveStructure && (
                 <div className="bg-strand-50 border border-strand-100 p-2 rounded text-[10px] text-strand-600 leading-tight">
                    <span className="font-bold text-strand-700">Form: </span> {lastActiveStructure}
                 </div>
             )}
          </div>
          <StyledSelect label="Seed Count" options={SEED_COUNTS} value={params.seedCount} onChange={(e) => onParamChange('seedCount', Number(e.target.value))} />
        </div>
      </div>

      <div className="pt-4 flex justify-center">
        <button
          onClick={onGenerate}
          disabled={loading}
          className={`flex items-center gap-2 px-8 py-4 rounded-full font-serif font-bold text-lg shadow-xl transition-all transform hover:-translate-y-1 ${loading ? 'bg-strand-200 text-strand-400' : 'bg-strand-800 text-white hover:bg-strand-900 ring-4 ring-white'}`}
        >
          {loading ? <><RefreshIcon className="w-5 h-5 animate-spin" /><span>Cultivating...</span></> : <><SparklesIcon className="w-5 h-5" /><span>Generate Seeds</span></>}
        </button>
      </div>
    </div>
  );
};

payload.text:
/**
 * Strandline Expedition (Road-Only) — minimal “dynamic journey” engine
 * ---------------------------------------------------------------
 * This is “text code” you can paste into Base44 / Gemini Studio / a TS project.
 * It’s intentionally map-free. No GPS needed. The journey is driven by STATE.
 *
 * Core idea:
 * - User completes a Segment (seed or prose)
 * - Engine updates JourneyState
 * - Engine proposes 3–5 contextual ContinuationOptions
 * - Optional “Situations” (weather, breakdowns) overlay constraints
 */

/** ---------- Types ---------- */

type Biome =
  | "coast"
  | "estuary"
  | "upland"
  | "forest"
  | "farmland"
  | "city_edge"
  | "industrial_margin"
  | "river_corridor"
  | "deserted_town";

type RoadState =
  | "cruising" // distance eats detail
  | "hunting" // frequent pullovers, verge attention
  | "stalled" // forced stillness
  | "night_driving" // tunnel vision + interior amplification
  | "weather_bound" // conditions dictate pace
  | "backroads" // slower, more porous
  | "town_drift"; // human proximity + interruption

type WeatherPressure = "calm" | "marginal" | "hostile";
type Fatigue = "fresh" | "worn" | "frayed";
type NarrativeTemp = "observational" | "lyrical" | "haunted" | "stripped";

type Shelter =
  | "vehicle"
  | "motel"
  | "remote_inn"
  | "wild_edge"; // lay-by / forestry margin / legal edge camp

type SituationType =
  | "fog"
  | "rain_cycle"
  | "wind_gale"
  | "heat_haze"
  | "road_closure"
  | "flat_tire"
  | "engine_warning"
  | "checkpoint"
  | "animal_on_road"
  | "roadworks";

interface Situation {
  type: SituationType;
  intensity: 1 | 2 | 3;
  /** How many segments it tends to persist (unknown to user). */
  remainingSegments: number;
  /** Modifiers that bias option generation & prose guidance. */
  optionBias?: Partial<Record<ContinuationType, number>>;
  prosePhysics?: Partial<ProsePhysics>;
}

type ContinuationType =
  | "continue_forward"
  | "divert_backroads"
  | "divert_inland"
  | "linger_pullover"
  | "enter_town"
  | "camp_hold"
  | "night_push"
  | "repair_wait"
  | "weather_delay"
  | "reverse_short"
  | "seek_shelter";

interface ProsePhysics {
  sentenceLengthBias: "short" | "mixed" | "long";
  sensoryBias: Array<"sound" | "sight" | "smell" | "touch" | "taste">;
  temporalPace: "compressed" | "normal" | "expanded";
  abstractionCeiling: "low" | "medium" | "high";
}

interface MotifTracker {
  birds: number;
  water: number;
  ruins: number;
  weather: number;
  human_residue: number;
  roads: number;
  silence: number;
}

interface VehicleState {
  interior: "clean" | "lived_in" | "cluttered";
  soundscape: "silence" | "radio" | "podcast";
  minorIssues: Array<"rattle" | "wipers_bad" | "warning_light">;
}

interface JourneyState {
  biome: Biome;
  roadState: RoadState;
  weatherPressure: WeatherPressure;
  fatigue: Fatigue;
  narrativeTemp: NarrativeTemp;
  lastShelter?: Shelter;
  situations: Situation[];
  motifs: MotifTracker;
  vehicle: VehicleState;

  /** History for repetition-avoidance */
  recentContinuations: ContinuationType[];
  segmentCount: number;
}

/** Segment completion payload (what user just did). */
interface SegmentResult {
  kind: "seed" | "prose" | "field_note";
  words?: number; // if prose
  chosenShelter?: Shelter; // if night/camp
  chosenContinuation?: ContinuationType; // what user picked last time
  motifDelta?: Partial<MotifTracker>; // optional manual tagging
}

/** What engine outputs. */
interface ContinuationOption {
  type: ContinuationType;
  label: string; // not gamey: “The road thins inland…”
  consequenceHint: string; // felt consequence, not stats
  proseHint?: string; // ambient guidance
}

/** ---------- Defaults ---------- */

const defaultMotifs: MotifTracker = {
  birds: 0,
  water: 0,
  ruins: 0,
  weather: 0,
  human_residue: 0,
  roads: 0,
  silence: 0,
};

const defaultJourneyState: JourneyState = {
  biome: "coast",
  roadState: "cruising",
  weatherPressure: "calm",
  fatigue: "fresh",
  narrativeTemp: "observational",
  lastShelter: undefined,
  situations: [],
  motifs: { ...defaultMotifs },
  vehicle: {
    interior: "lived_in",
    soundscape: "silence",
    minorIssues: [],
  },
  recentContinuations: [],
  segmentCount: 0,
};

/** ---------- Utility helpers ---------- */

function clamp(n: number, lo: number, hi: number) {
  return Math.max(lo, Math.min(hi, n));
}

function pickTopN<T extends { score: number }>(items: T[], n: number): T[] {
  return [...items].sort((a, b) => b.score - a.score).slice(0, n);
}

function pushRecent<T>(arr: T[], item: T, max = 6): T[] {
  const next = [item, ...arr];
  return next.slice(0, max);
}

/** ---------- Prose physics (ambient, not commands) ---------- */

function computeProsePhysics(state: JourneyState): ProsePhysics {
  // Start with baseline
  let physics: ProsePhysics = {
    sentenceLengthBias: "mixed",
    sensoryBias: ["sight", "sound", "smell"],
    temporalPace: "normal",
    abstractionCeiling: "medium",
  };

  // RoadState influences perception
  if (state.roadState === "night_driving") {
    physics.sensoryBias = ["sound", "sight", "touch"];
    physics.temporalPace = "compressed";
    physics.abstractionCeiling = "low";
  }
  if (state.roadState === "stalled") {
    physics.sensoryBias = ["sound", "smell", "touch", "sight"];
    physics.temporalPace = "expanded";
    physics.sentenceLengthBias = "long";
  }
  if (state.roadState === "hunting" || state.roadState === "backroads") {
    physics.abstractionCeiling = "low";
    physics.temporalPace = "expanded";
  }

  // WeatherPressure
  if (state.weatherPressure === "hostile") {
    physics.abstractionCeiling = "low";
    physics.sentenceLengthBias = "short";
    physics.sensoryBias = ["sound", "touch", "sight"];
  }

  // Narrative temperature
  if (state.narrativeTemp === "stripped") {
    physics.sentenceLengthBias = "short";
    physics.abstractionCeiling = "low";
  }
  if (state.narrativeTemp === "lyrical") {
    physics.sentenceLengthBias = "long";
    physics.abstractionCeiling = "high";
  }

  // Situations can override/tilt
  for (const s of state.situations) {
    if (s.prosePhysics) {
      physics = { ...physics, ...s.prosePhysics };
      // If sensoryBias present, prefer it
      if (s.prosePhysics.sensoryBias) physics.sensoryBias = s.prosePhysics.sensoryBias;
    }
  }

  return physics;
}

/** ---------- State update on segment completion ---------- */

function applyMotifDelta(motifs: MotifTracker, delta?: Partial<MotifTracker>): MotifTracker {
  if (!delta) return motifs;
  const next = { ...motifs };
  for (const k of Object.keys(delta) as (keyof MotifTracker)[]) {
    next[k] = clamp((next[k] ?? 0) + (delta[k] ?? 0), 0, 999);
  }
  return next;
}

function decaySituations(situations: Situation[]): Situation[] {
  return situations
    .map((s) => ({ ...s, remainingSegments: s.remainingSegments - 1 }))
    .filter((s) => s.remainingSegments > 0);
}

function updateStateOnSegmentComplete(state: JourneyState, result: SegmentResult): JourneyState {
  let next: JourneyState = { ...state };

  next.segmentCount += 1;

  // Record shelter if provided
  if (result.chosenShelter) next.lastShelter = result.chosenShelter;

  // Track recent continuation choices to avoid repetition
  if (result.chosenContinuation) {
    next.recentContinuations = pushRecent(next.recentContinuations, result.chosenContinuation, 6);
  }

  // Motifs (manual tagging or auto heuristics could be added later)
  next.motifs = applyMotifDelta(next.motifs, result.motifDelta);

  // Fatigue drift (simple, tuneable)
  if (result.kind === "prose" && (result.words ?? 0) > 600) {
    // Long writing session tends to “tire” in-world
    next.fatigue = next.fatigue === "fresh" ? "worn" : next.fatigue === "worn" ? "frayed" : "frayed";
  }

  // Shelter affects fatigue recovery
  if (result.chosenShelter) {
    if (result.chosenShelter === "motel" || result.chosenShelter === "remote_inn") {
      next.fatigue = next.fatigue === "frayed" ? "worn" : "fresh";
    }
    if (result.chosenShelter === "vehicle") {
      next.fatigue = next.fatigue === "fresh" ? "fresh" : "worn";
    }
    if (result.chosenShelter === "wild_edge") {
      // Wild edge = restorative OR draining depending on weather pressure
      next.fatigue =
        next.weatherPressure === "hostile"
          ? next.fatigue === "fresh"
            ? "worn"
            : "frayed"
          : next.fatigue === "frayed"
            ? "worn"
            : "fresh";
    }
  }

  // Situations decay
  next.situations = decaySituations(next.situations);

  return next;
}

/** ---------- Situation injection (controlled friction) ---------- */

function maybeInjectSituation(state: JourneyState): JourneyState {
  // Guardrail: don’t stack too many frictions
  if (state.situations.length >= 1) return state;

  // Simple probability logic (tune as you like)
  let p = 0.12; // base chance
  if (state.weatherPressure === "hostile") p += 0.10;
  if (state.fatigue === "frayed") p += 0.08;
  if (state.roadState === "night_driving") p += 0.05;

  // Random roll (replace with deterministic seed if needed)
  if (Math.random() > p) return state;

  // Choose a situation weighted by context
  const candidates: Array<{ type: SituationType; weight: number; mk: () => Situation }> = [
    {
      type: "fog",
      weight: state.weatherPressure !== "calm" ? 3 : 1,
      mk: () => ({
        type: "fog",
        intensity: state.weatherPressure === "hostile" ? 3 : 2,
        remainingSegments: 1 + Math.floor(Math.random() * 2),
        optionBias: { weather_delay: 3, night_push: -2, linger_pullover: 2 },
        prosePhysics: { sensoryBias: ["sound", "sight", "touch"], abstractionCeiling: "low" },
      }),
    },
    {
      type: "rain_cycle",
      weight: 3,
      mk: () => ({
        type: "rain_cycle",
        intensity: state.weatherPressure === "hostile" ? 3 : 2,
        remainingSegments: 2 + Math.floor(Math.random() * 2),
        optionBias: { seek_shelter: 2, camp_hold: 1, divert_backroads: 1 },
        prosePhysics: { sensoryBias: ["sound", "smell", "touch"], temporalPace: "expanded" },
      }),
    },
    {
      type: "flat_tire",
      weight: state.vehicle.minorIssues.includes("warning_light") ? 3 : 1,
      mk: () => ({
        type: "flat_tire",
        intensity: 2,
        remainingSegments: 1,
        optionBias: { repair_wait: 4, continue_forward: -3, night_push: -2 },
        prosePhysics: { temporalPace: "expanded", abstractionCeiling: "low" },
      }),
    },
    {
      type: "animal_on_road",
      weight: state.biome === "forest" || state.biome === "upland" ? 3 : 1,
      mk: () => ({
        type: "animal_on_road",
        intensity: 2,
        remainingSegments: 1,
        optionBias: { linger_pullover: 3, continue_forward: -1 },
        prosePhysics: { abstractionCeiling: "low", sensoryBias: ["sight", "sound"] },
      }),
    },
    {
      type: "roadworks",
      weight: state.roadState === "cruising" ? 2 : 1,
      mk: () => ({
        type: "roadworks",
        intensity: 1,
        remainingSegments: 1,
        optionBias: { divert_backroads: 2, continue_forward: 1, linger_pullover: 1 },
        prosePhysics: { temporalPace: "compressed" },
      }),
    },
  ];

  const total = candidates.reduce((sum, c) => sum + c.weight, 0);
  let r = Math.random() * total;
  let chosen = candidates[0];
  for (const c of candidates) {
    r -= c.weight;
    if (r <= 0) {
      chosen = c;
      break;
    }
  }

  return { ...state, situations: [chosen.mk()] };
}

/** ---------- Continuation generation (weighted offers, not branches) ---------- */

function baseContinuationPool(state: JourneyState): Array<{ type: ContinuationType; score: number }> {
  // Start with a neutral pool
  const pool: Array<{ type: ContinuationType; score: number }> = [
    { type: "continue_forward", score: 10 },
    { type: "divert_backroads", score: 8 },
    { type: "divert_inland", score: 6 },
    { type: "linger_pullover", score: 7 },
    { type: "enter_town", score: 6 },
    { type: "camp_hold", score: 6 },
    { type: "night_push", score: 5 },
    { type: "repair_wait", score: 4 },
    { type: "weather_delay", score: 5 },
    { type: "reverse_short", score: 3 },
    { type: "seek_shelter", score: 6 },
  ];

  // Bias by road state
  if (state.roadState === "cruising") {
    add(pool, "continue_forward", 2);
    add(pool, "linger_pullover", -2);
  }
  if (state.roadState === "hunting") {
    add(pool, "linger_pullover", 3);
    add(pool, "divert_backroads", 2);
  }
  if (state.roadState === "stalled") {
    add(pool, "repair_wait", 4);
    add(pool, "weather_delay", 2);
    add(pool, "continue_forward", -4);
  }
  if (state.roadState === "night_driving") {
    add(pool, "seek_shelter", 3);
    add(pool, "night_push", 2);
    add(pool, "enter_town", -1);
  }
  if (state.roadState === "weather_bound") {
    add(pool, "weather_delay", 4);
    add(pool, "seek_shelter", 2);
    add(pool, "continue_forward", -3);
  }

  // Weather pressure
  if (state.weatherPressure === "hostile") {
    add(pool, "seek_shelter", 3);
    add(pool, "weather_delay", 3);
    add(pool, "night_push", -2);
  }

  // Fatigue
  if (state.fatigue === "frayed") {
    add(pool, "camp_hold", 3);
    add(pool, "seek_shelter", 2);
    add(pool, "continue_forward", -2);
  }

  // Avoid repetition: penalize recently chosen continuations
  for (const recent of state.recentContinuations) {
    add(pool, recent, -2);
  }

  // Situation overlays
  for (const s of state.situations) {
    if (s.optionBias) {
      for (const [k, v] of Object.entries(s.optionBias) as [ContinuationType, number][]) {
        add(pool, k, v);
      }
    }
  }

  return pool;
}

function add(pool: Array<{ type: ContinuationType; score: number }>, type: ContinuationType, delta: number) {
  const item = pool.find((p) => p.type === type);
  if (item) item.score += delta;
}

function optionCopy(type: ContinuationType, state: JourneyState, physics: ProsePhysics): ContinuationOption {
  // Keep labels “felt”, not “game UI”.
  // You can expand this library indefinitely.
  const byType: Record<ContinuationType, Omit<ContinuationOption, "type">> = {
    continue_forward: {
      label: "Keep the line of travel. Let distance thin the details.",
      consequenceHint: "You’ll pass more than you can stop for; the world becomes a moving margin.",
      proseHint: proseHint(physics),
    },
    divert_backroads: {
      label: "Take the smaller roads. Make the journey more porous.",
      consequenceHint: "Progress slows, but the edges begin to speak—ditches, gates, birds, culverts.",
      proseHint: proseHint(physics),
    },
    divert_inland: {
      label: "Turn away from the edge. Let the coast fall silent behind you.",
      consequenceHint: "Human patterns intensify; the sea becomes memory pressure rather than presence.",
      proseHint: proseHint(physics),
    },
    linger_pullover: {
      label: "Pull over. Give a place a right to exist in full.",
      consequenceHint: "A small radius deepens into a whole world—sound, smell, drift, residue.",
      proseHint: proseHint({ ...physics, temporalPace: "expanded", abstractionCeiling: "low" }),
    },
    enter_town: {
      label: "Enter the town, not as a stop, but as a weather system of people.",
      consequenceHint: "Voices and signage intrude; you pick up residue you didn’t ask for.",
      proseHint: proseHint(physics),
    },
    camp_hold: {
      label: "Hold position. Make stillness legitimate.",
      consequenceHint: "The same scene changes with light; repetition becomes revelation or irritation.",
      proseHint: proseHint({ ...physics, temporalPace: "expanded" }),
    },
    night_push: {
      label: "Drive into darkness. Narrow the world to headlights and breath.",
      consequenceHint: "Detail collapses; interior sound and fatigue become dominant facts.",
      proseHint: proseHint({ ...physics, abstractionCeiling: "low" }),
    },
    repair_wait: {
      label: "Stop and wait. Work within ten meters like it’s a continent.",
      consequenceHint: "The ditch, the verge, the fence-line: attention becomes the only vehicle.",
      proseHint: proseHint({ ...physics, temporalPace: "expanded", abstractionCeiling: "low" }),
    },
    weather_delay: {
      label: "Let weather dictate terms. Delay without apology.",
      consequenceHint: "Time stretches; small noises become structure. The journey turns inward.",
      proseHint: proseHint({ ...physics, temporalPace: "expanded" }),
    },
    reverse_short: {
      label: "Double back briefly. Revisit a threshold you didn’t read properly.",
      consequenceHint: "You’ll see what you missed; memory and place argue in the same frame.",
      proseHint: proseHint(physics),
    },
    seek_shelter: {
      label: "Seek shelter. Choose the kind of night you can survive.",
      consequenceHint: "Where you sleep will change what the next day is allowed to feel like.",
      proseHint: proseHint(physics),
    },
  };

  return { type, ...byType[type] };
}

function proseHint(physics: ProsePhysics): string {
  const s = physics.sentenceLengthBias;
  const t = physics.temporalPace;
  const a = physics.abstractionCeiling;
  const senses = physics.sensoryBias.join(", ");
  return `Prose physics: ${s} sentences · ${t} time · abstraction ${a} · bias: ${senses}.`;
}

function generateContinuationOptions(state: JourneyState, count = 4): ContinuationOption[] {
  const physics = computeProsePhysics(state);
  const pool = baseContinuationPool(state);

  const scored = pool.map((p) => ({
    ...p,
    // Hard floor to avoid negative scores taking over
    score: clamp(p.score, -10, 50),
  }));

  const top = pickTopN(scored, count + 2) // take a few extra
    .filter((p) => p.score > 0);

  // Ensure variety: don’t return only “rest/shelter” options
  const unique: ContinuationOption[] = [];
  const used = new Set<ContinuationType>();

  for (const cand of top) {
    if (used.has(cand.type)) continue;
    unique.push(optionCopy(cand.type, state, physics));
    used.add(cand.type);
    if (unique.length >= count) break;
  }

  // Fallback if everything got suppressed
  if (unique.length < 3) {
    unique.push(optionCopy("continue_forward", state, physics));
    unique.push(optionCopy("linger_pullover", state, physics));
    unique.push(optionCopy("seek_shelter", state, physics));
  }

  return unique;
}

/** ---------- Orchestrator (one “turn” of the engine) ---------- */

interface EngineOutput {
  nextState: JourneyState;
  prosePhysics: ProsePhysics;
  options: ContinuationOption[];
}

function expeditionTurn(state: JourneyState, segment: SegmentResult): EngineOutput {
  // 1) Update state based on what user completed
  let nextState = updateStateOnSegmentComplete(state, segment);

  // 2) Maybe inject a single, survivable situation (controlled friction)
  nextState = maybeInjectSituation(nextState);

  // 3) Compute ambient prose physics and generate options
  const physics = computeProsePhysics(nextState);
  const options = generateContinuationOptions(nextState, 4);

  return {
    nextState,
    prosePhysics: physics,
    options,
  };
}

/** ---------- Example usage ---------- */

// Starting state
let state = { ...defaultJourneyState };

// User completes a segment (prose)
const result: SegmentResult = {
  kind: "prose",
  words: 820,
  chosenShelter: "vehicle",
  chosenContinuation: "continue_forward",
  motifDelta: { weather: 1, roads: 1, silence: 1 },
};

// Engine responds
const out = expeditionTurn(state, result);

// Save next state (localStorage, database, etc.)
state = out.nextState;

// Display options to user
console.log("Prose Physics:", out.prosePhysics);
console.log("Next Options:");
for (const o of out.options) {
  console.log("-", o.label);
  console.log("  ↳", o.consequenceHint);
  console.log("  ↳", o.proseHint);
}

