  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            profileText: { 
              type: Type.STRING, 
              description: "A detailed literary characterization and breakdown of the author mix." 
            },
            suggestions: {
              type: Type.OBJECT,
              properties: {
                suggestedLocations: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING } 
                },
                suggestedBiomes: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING } 
                },
                thematicSeeds: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING } 
                }
              },
              required: ["suggestedLocations", "suggestedBiomes", "thematicSeeds"]
            }
          },
          required: ["profileText", "suggestions"]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Voice Profile Error:", error);
    throw error;
  }
};

